import { notFound } from "next/navigation";
import Link from "next/link";
import { requireAuth } from "@/lib/auth";
import { getPartById, PARTS } from "@/lib/content";
import { ERA_MAP } from "@/lib/types";
import {
  readBriefing,
  readStatementOfFacts,
  readStudyGuide,
  readReport,
  getSlideFiles,
  getInfographicFilename,
  mindmapExists,
  readQuiz,
  readFlashcards,
  getPartAssetUrls,
} from "@/lib/files";
import { getR2AssetUrl, generateSignedR2Url, IMAGE_URL_EXPIRY } from "@/lib/r2";
import { ChevronLeft, ChevronRight, Clock, BookOpen, Star } from "lucide-react";
import { PartTabs } from "@/components/part/part-tabs";
import { CourseContentsDrawer } from "@/components/part/course-contents-drawer";

export async function generateStaticParams() {
  return PARTS.map((p) => ({ partId: p.id }));
}

export async function generateMetadata(props: { params: Promise<{ partId: string }> }) {
  const { partId } = await props.params;
  const part = getPartById(partId);
  if (!part) return { title: "Part Not Found" };
  return {
    title: `Part ${part.partNumber}: ${part.title}`,
    description: part.description,
  };
}

export default async function PartPage(props: { params: Promise<{ partId: string }> }) {
  const user = await requireAuth();
  const { partId } = await props.params;

  const partBase = getPartById(partId);
  if (!partBase) notFound();

  const n = partBase.partNumber;

  // Legacy route - default to complete plan for backward compatibility
  const userPlan = "complete" as const;

  // Load assets from R2
  const [
    briefingText,
    statementOfFactsText,
    studyGuideText,
    reportText,
    quiz,
    flashcards,
    slidesPresentedFiles,
    slidesDetailedFiles,
    slidesFactsFiles,
    infConcise,
    infStandard,
    infBento,
    hasMindmap,
    assetUrls,
  ] = await Promise.all([
    readBriefing(n),
    readStatementOfFacts(n),
    readStudyGuide(n),
    readReport(n),
    readQuiz(n),
    readFlashcards(n),
    getSlideFiles(n, "presented"),
    getSlideFiles(n, "detailed"),
    getSlideFiles(n, "facts"),
    getInfographicFilename(n, "Concise"),
    getInfographicFilename(n, "Standard"),
    getInfographicFilename(n, "Bento Grid"),
    mindmapExists(n),
    getPartAssetUrls(n),
  ]);

  const slideFiles = {
    presented: slidesPresentedFiles,
    detailed: slidesDetailedFiles,
    facts: slidesFactsFiles,
  };

  const part = {
    ...partBase,
    assets: {
      ...partBase.assets,
      videoUrl: assetUrls.videoUrl ?? undefined,
      audioUrl: assetUrls.audioUrl ?? undefined,
      briefingText: briefingText ?? undefined,
      statementOfFactsText: statementOfFactsText ?? undefined,
      studyGuideText: studyGuideText ?? undefined,
      reportText: reportText ?? undefined,
      mindmapUrl: assetUrls.mindmapUrl ?? undefined,
      quiz: quiz ?? undefined,
      flashcards: flashcards ?? undefined,
      slides: slideFiles,
      infographics: await (async () => {
        // R2 keys contain "/" ΓÇö sign them. Local filenames don't contain "/" ΓÇö use local path.
        const sign = (key: string | null, localFolder: string) =>
          key
            ? key.includes("/")
              ? generateSignedR2Url(key, IMAGE_URL_EXPIRY)
              : Promise.resolve(`/seerah-media/Infographics/${localFolder}/${key}`)
            : Promise.resolve(undefined);

        const [concise, standard, bentoGrid] = await Promise.all([
          sign(infConcise, "Concise"),
          sign(infStandard, "Standard"),
          sign(infBento, "Bento Grid"),
        ]);
        return { concise, standard, bentoGrid };
      })(),
    },
  };

  const era = ERA_MAP[part.era];
  const allParts = PARTS;
  const currentIndex = allParts.findIndex((p) => p.id === partId);
  const prevPart = currentIndex > 0 ? allParts[currentIndex - 1] : null;
  const nextPart = currentIndex < allParts.length - 1 ? allParts[currentIndex + 1] : null;
  const totalParts = allParts.length;
  const progressPct = Math.round(((currentIndex + 1) / totalParts) * 100);

  return (
    <div className="min-h-full">

      {/* ΓöÇΓöÇ Breadcrumb + course progress ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 pt-5 sm:pt-6">
        <div className="flex items-center justify-between gap-6">
          <div className="flex items-center gap-3">
            <nav className="flex items-center gap-2 text-xs text-text-muted">
              <Link href="/dashboard" className="hover:text-text-secondary transition-colors">Dashboard</Link>
              <ChevronRight className="w-3 h-3 opacity-40" />
              <Link href="/parts" className="hover:text-text-secondary transition-colors">All Parts</Link>
              <ChevronRight className="w-3 h-3 opacity-40" />
              <span className="text-text-secondary">Part {part.partNumber}</span>
            </nav>
            <CourseContentsDrawer allParts={allParts} currentPartId={partId} />
          </div>

          <div className="flex items-center gap-3 flex-shrink-0">
            <span className="text-[11px] text-text-muted tabular-nums hidden sm:block">
              Part {currentIndex + 1} of {totalParts}
            </span>
            <div className="w-24 sm:w-36 h-[3px] bg-surface-high rounded-full overflow-hidden">
              <div
                className="h-full bg-gradient-to-r from-gold/80 to-gold rounded-full transition-all"
                style={{ width: `${progressPct}%` }}
              />
            </div>
            <span className="text-[11px] text-gold/70 tabular-nums font-medium">{progressPct}%</span>
          </div>
        </div>
      </div>

      {/* ΓöÇΓöÇ Hero panel ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 mt-5 mb-6">
        <div className="rounded-2xl bg-surface border border-border/70 overflow-hidden">
          {/* Top gold accent line */}
          <div className="h-px w-full bg-gradient-to-r from-transparent via-gold/35 to-transparent" />

          <div className="p-6 sm:p-8">
            {/* Metadata row */}
            <div className="flex flex-wrap items-center gap-2 mb-5">
              <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-gold/12 border border-gold/25 text-gold text-xs font-semibold">
                Part {part.partNumber}
              </span>
              {era && (
                <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-surface-raised border border-border text-text-secondary text-xs font-medium">
                  <span
                    className="w-1.5 h-1.5 rounded-full flex-shrink-0"
                    style={{ backgroundColor: era.color }}
                  />
                  {era.label}
                </span>
              )}
              {part.duration && (
                <span className="inline-flex items-center gap-1.5 text-xs text-text-muted">
                  <Clock className="w-3 h-3" />
                  {part.duration}
                </span>
              )}
            </div>

            {/* Title */}
            <h1 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-text leading-tight tracking-tight">
              {part.title}
            </h1>
            {part.subtitle && (
              <p className="mt-2 text-base sm:text-lg text-text-secondary leading-snug">
                {part.subtitle}
              </p>
            )}

            {/* Description callout */}
            <div className="mt-6 flex gap-4 p-4 sm:p-5 rounded-xl bg-surface-raised border border-border/60">
              <div className="flex-shrink-0 mt-0.5">
                <div className="w-7 h-7 rounded-lg bg-gold/10 border border-gold/20 flex items-center justify-center">
                  <BookOpen className="w-3.5 h-3.5 text-gold/70" />
                </div>
              </div>
              <div>
                <p className="text-[11px] font-semibold uppercase tracking-widest text-gold/60 mb-1.5">
                  About this lesson
                </p>
                <p className="text-sm text-text-secondary leading-relaxed">
                  {part.description}
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* ΓöÇΓöÇ Learning modes + content ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <PartTabs part={part} userPlan={userPlan} />
      </div>

      {/* ΓöÇΓöÇ Continue learning ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      {(prevPart || nextPart || part.partNumber === 100) && (
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 mt-14 pb-12">
          <div className="flex items-center gap-3 mb-5">
            <div className="h-px flex-1 bg-border/60" />
            <span className="text-[10px] font-semibold tracking-[0.2em] uppercase text-text-muted">
              Continue the journey
            </span>
            <div className="h-px flex-1 bg-border/60" />
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {/* Previous */}
            <div>
              {prevPart ? (
                <Link
                  href={`/parts/${prevPart.id}`}
                  prefetch={false}
                  className="group flex flex-col gap-2.5 p-5 rounded-xl border border-border bg-surface hover:border-border-subtle hover:bg-surface-raised transition-all duration-200 h-full"
                >
                  <div className="flex items-center gap-1.5 text-[11px] text-text-muted group-hover:text-text-secondary transition-colors">
                    <ChevronLeft className="w-3 h-3" />
                    <span>Previous lesson</span>
                  </div>
                  <div>
                    <p className="text-sm font-semibold text-text leading-snug line-clamp-2 group-hover:text-text transition-colors">
                      {prevPart.title}
                    </p>
                    {prevPart.subtitle && (
                      <p className="text-xs text-text-muted mt-1 line-clamp-1">{prevPart.subtitle}</p>
                    )}
                  </div>
                </Link>
              ) : <div />}
            </div>

            {/* Next ΓÇö regular part or Conclusion if on Part 100 */}
            <div>
              {nextPart ? (
                <Link
                  href={`/parts/${nextPart.id}`}
                  prefetch={false}
                  className="group relative flex flex-col gap-2.5 p-5 rounded-xl border border-gold/25 bg-gradient-to-br from-gold/8 to-gold/4 hover:border-gold/40 hover:from-gold/12 hover:to-gold/6 transition-all duration-200 h-full overflow-hidden"
                >
                  <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-gold/30 to-transparent" />
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-semibold uppercase tracking-widest text-gold/60">Up next</span>
                    <ChevronRight className="w-3.5 h-3.5 text-gold/50 group-hover:text-gold group-hover:translate-x-0.5 transition-all" />
                  </div>
                  <div>
                    <p className="text-sm font-semibold text-text leading-snug line-clamp-2">{nextPart.title}</p>
                    {nextPart.subtitle && (
                      <p className="text-xs text-text-muted mt-1 line-clamp-1">{nextPart.subtitle}</p>
                    )}
                  </div>
                  {nextPart.duration && (
                    <div className="flex items-center gap-1 text-[11px] text-text-muted mt-auto pt-1">
                      <Clock className="w-3 h-3" />
                      {nextPart.duration}
                    </div>
                  )}
                </Link>
              ) : part.partNumber === 100 ? (
                <Link
                  href="/conclusion"
                  className="group relative flex flex-col gap-2.5 p-5 rounded-xl border border-gold/40 bg-gradient-to-br from-gold/12 to-gold/6 hover:border-gold/60 hover:from-gold/18 hover:to-gold/10 transition-all duration-200 h-full overflow-hidden"
                >
                  <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-gold/50 to-transparent" />
                  <div className="flex items-center justify-between">
                    <span className="inline-flex items-center gap-1 text-[10px] font-semibold uppercase tracking-widest text-gold/70">
                      <Star className="w-2.5 h-2.5 fill-gold/50" />
                      Final Video
                    </span>
                    <ChevronRight className="w-3.5 h-3.5 text-gold/50 group-hover:text-gold group-hover:translate-x-0.5 transition-all" />
                  </div>
                  <div>
                    <p className="text-sm font-semibold text-gold leading-snug">The Final Conclusion</p>
                    <p className="text-xs text-text-muted mt-1">A closing reflection on the life of the Prophet ∩╖║</p>
                  </div>
                  <p className="text-[10px] text-gold/50 mt-auto pt-1">Complete the course ΓåÆ</p>
                </Link>
              ) : null}
            </div>
          </div>
        </div>
      )}

    </div>
  );
}

import { prisma } from "@/lib/db";
import { requireAdmin } from "@/lib/auth";
import { BookOpen, Plus } from "lucide-react";
import Link from "next/link";

export const metadata = { title: "Courses" };
export const dynamic = "force-dynamic";

export default async function AdminCoursesPage() {
  await requireAdmin();
  
  // Courses are platform-owned curriculum products
  // Using course templates as the foundation
  const courses = await prisma.courseTemplate.findMany({
    where: { isActive: true },
    include: { 
      _count: { select: { items: true, classCourses: true } },
    },
    orderBy: { createdAt: "desc" },
  });

  return (
    <div className="p-4 sm:p-6 lg:p-8 max-w-6xl mx-auto">
      <div className="mb-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl sm:text-3xl font-bold text-text mb-1">Courses</h1>
            <p className="text-text-secondary text-sm">
              Platform-owned curriculum products offered to students.
            </p>
          </div>
          {/* Add course button for future */}
          <button
            disabled
            className="px-4 py-2 rounded-lg bg-gold/10 text-gold border border-gold/30 text-sm font-medium opacity-50 cursor-not-allowed"
          >
            <Plus className="w-4 h-4 inline mr-1" />
            Add Course
          </button>
        </div>
      </div>

      {courses.length === 0 ? (
        <div className="text-center py-12 rounded-2xl border border-border bg-surface">
          <BookOpen className="w-12 h-12 text-slate-300 mx-auto mb-3" />
          <p className="text-text-muted">No courses yet</p>
          <p className="text-sm text-text-secondary mt-1">
            Courses like "Full Seerah ΓÇö All 100 Parts" will appear here
          </p>
        </div>
      ) : (
        <div className="space-y-4">
          {courses.map((course) => (
            <div key={course.id} className="p-6 rounded-2xl border border-border bg-surface hover:border-gold/30 transition-all">
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <BookOpen className="w-5 h-5 text-gold" />
                    <h3 className="text-lg font-semibold text-text">{course.title}</h3>
                  </div>
                  {course.description && (
                    <p className="text-sm text-text-secondary mb-3">{course.description}</p>
                  )}
                  <div className="flex items-center gap-4 text-xs text-text-muted">
                    <span>{course._count.items} lessons</span>
                    <span>ΓÇó</span>
                    <span>Used in {course._count.classCourses} programs</span>
                  </div>
                </div>
                <div className="flex flex-col gap-2">
                  <span className="inline-flex items-center px-2.5 py-1 rounded-full bg-green-100 text-green-700 text-xs font-medium">
                    Published
                  </span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Info box */}
      <div className="mt-8 p-4 rounded-xl bg-blue-50 border border-blue-200">
        <p className="text-sm text-blue-900 font-medium mb-1">About Courses</p>
        <p className="text-xs text-blue-700">
          Courses are the core curriculum products (like "Full Seerah" or future courses). 
          Programs use courses as their curriculum and add scheduling, enrollment, and delivery rules.
        </p>
      </div>
    </div>
  );
}

import { redirect } from "next/navigation";
import { requireAuth } from "@/lib/auth";
import { r2ListFolders, r2ListFiles } from "@/lib/r2";
import { Check, X, Folder, FileIcon, RefreshCw, ChevronRight } from "lucide-react";
import Link from "next/link";

export const dynamic = "force-dynamic";

async function checkR2Connection() {
  try {
    const folders = await r2ListFolders();
    return {
      connected: true,
      folders: folders.length,
      error: null,
    };
  } catch (error: any) {
    return {
      connected: false,
      folders: 0,
      error: error.message || "Unknown error",
    };
  }
}

export default async function R2AdminPage({
  searchParams,
}: {
  searchParams: Promise<{ bucket?: string; folder?: string }>;
}) {
  const user = await requireAuth();
  
  // Only admins can access this page
  if (user.role !== "platform_admin") {
    redirect("/dashboard");
  }

  const { bucket, folder } = await searchParams;

  // Check R2 connection
  const connectionStatus = await checkR2Connection();
  
  // Get folders and files
  let folders: string[] = [];
  let files: Array<{ key: string; size: number; lastModified?: Date }> = [];
  
  if (connectionStatus.connected && bucket) {
    if (folder) {
      files = await r2ListFiles(folder);
    } else {
      folders = await r2ListFolders();
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-b from-slate-50 to-white">
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        
        {/* Header */}
        <div className="mb-8">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl font-bold text-slate-900">R2 Storage Manager</h1>
              <p className="text-slate-600 mt-2">
                {!bucket 
                  ? "Select a storage bucket to manage" 
                  : "Manage and browse your Cloudflare R2 media assets"}
              </p>
            </div>
            <Link
              href="/admin/dashboard"
              className="px-4 py-2 rounded-lg bg-slate-100 text-slate-700 hover:bg-slate-200 transition-colors"
            >
              Back to Dashboard
            </Link>
          </div>
        </div>

        {/* Connection Status Card */}
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-6 mb-6">
          <div className="flex items-start gap-4">
            <div className={`mt-1 rounded-full p-2 ${
              connectionStatus.connected 
                ? "bg-green-100" 
                : "bg-red-100"
            }`}>
              {connectionStatus.connected ? (
                <Check className="w-5 h-5 text-green-600" />
              ) : (
                <X className="w-5 h-5 text-red-600" />
              )}
            </div>
            <div className="flex-1">
              <h2 className="text-lg font-semibold text-slate-900 mb-1">
                Connection Status
              </h2>
              {connectionStatus.connected ? (
                <div>
                  <p className="text-green-600 font-medium">Connected to R2</p>
                  <p className="text-sm text-slate-600 mt-1">
                    Found {connectionStatus.folders} top-level folders
                  </p>
                  <div className="mt-3 grid grid-cols-2 gap-4 text-sm">
                    <div>
                      <span className="text-slate-500">Account ID:</span>
                      <p className="font-mono text-slate-900">{process.env.R2_ACCOUNT_ID}</p>
                    </div>
                    <div>
                      <span className="text-slate-500">Bucket:</span>
                      <p className="font-mono text-slate-900">{process.env.R2_BUCKET}</p>
                    </div>
                  </div>
                </div>
              ) : (
                <div>
                  <p className="text-red-600 font-medium">Connection Failed</p>
                  <p className="text-sm text-slate-600 mt-1">{connectionStatus.error}</p>
                  <div className="mt-3 p-3 bg-slate-50 rounded-lg">
                    <p className="text-xs text-slate-600">
                      Make sure your R2 credentials are correctly configured in your .env file.
                    </p>
                  </div>
                </div>
              )}
            </div>
            <form>
              <button
                type="submit"
                className="p-2 rounded-lg bg-slate-100 hover:bg-slate-200 transition-colors"
                title="Refresh"
              >
                <RefreshCw className="w-5 h-5 text-slate-600" />
              </button>
            </form>
          </div>
        </div>

        {/* Breadcrumb */}
        {bucket && (
          <div className="mb-4">
            <nav className="flex items-center gap-2 text-sm">
              <Link
                href="/admin/r2"
                className="text-slate-600 hover:text-slate-900 transition-colors"
              >
                Buckets
              </Link>
              <span className="text-slate-400">/</span>
              <Link
                href={`/admin/r2?bucket=seerah`}
                className="text-slate-600 hover:text-slate-900 transition-colors"
              >
                Seerah Media
              </Link>
              {folder && (
                <>
                  <span className="text-slate-400">/</span>
                  <span className="text-slate-900 font-medium">{folder.replace(/\/$/, "")}</span>
                </>
              )}
            </nav>
          </div>
        )}

        {/* Bucket Selection or Browser */}
        {!bucket ? (
          /* Bucket Selection */
          <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="px-6 py-4 border-b border-slate-200 bg-slate-50">
              <h2 className="font-semibold text-slate-900">Available Storage Buckets</h2>
            </div>
            
            <div className="p-6">
              <Link
                href="/admin/r2?bucket=seerah"
                className="group block p-6 rounded-xl border-2 border-slate-200 hover:border-blue-500 hover:bg-blue-50/50 transition-all"
              >
