          {/* Signup Form */}
          <div className="lg:col-span-3">
            <div className="bg-surface border border-border rounded-2xl p-6 sm:p-8">
              <form onSubmit={handleSubmit} className="space-y-4">
                <h2 className="text-lg font-semibold mb-6">Account Details</h2>

                <Input
                  label="Full name"
                  type="text"
                  placeholder="Your full name"
                  value={form.fullName}
                  onChange={(e) => setForm({ ...form, fullName: e.target.value })}
                  required
                  autoComplete="name"
                />

                <Input
                  label="Email address"
                  type="email"
                  placeholder="you@example.com"
                  value={form.email}
                  onChange={(e) => setForm({ ...form, email: e.target.value })}
                  required
                  autoComplete="email"
                />

                <div className="relative">
                  <Input
                    label="Password"
                    type={showPassword ? "text" : "password"}
                    placeholder="At least 8 characters"
                    value={form.password}
                    onChange={(e) => setForm({ ...form, password: e.target.value })}
                    required
                    autoComplete="new-password"
                    minLength={8}
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3 top-9 text-text-muted hover:text-text-secondary transition-colors"
                    aria-label={showPassword ? "Hide password" : "Show password"}
                  >
                    {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                  </button>
                </div>

                <Input
                  label="Confirm password"
                  type={showPassword ? "text" : "password"}
                  placeholder="Re-enter password"
                  value={form.confirmPassword}
                  onChange={(e) => setForm({ ...form, confirmPassword: e.target.value })}
                  required
                  autoComplete="new-password"
                  minLength={8}
                />

                {error && (
                  <div className="p-3 rounded-lg bg-red-500/10 border border-red-500/20 text-red-400 text-sm">
                    {error}
                  </div>
                )}

                <div className="pt-2">
                  <p className="text-sm text-text-muted mb-4">
                    After creating your account, you'll be redirected to complete your payment.
                  </p>

                  <Button
                    type="submit"
                    variant="primary"
                    size="lg"
                    className="w-full justify-center"
                    loading={loading}
                    disabled={loading}
                  >
                    Create Account & Continue
                    <ArrowRight className="w-4 h-4" />
                  </Button>

                  <p className="text-xs text-text-muted text-center mt-3 leading-relaxed">
                    By creating an account, you agree to our{" "}
                    <Link
                      href="/terms"
                      className="underline hover:text-text-secondary transition-colors"
                    >
                      Terms of Service
                    </Link>
                    {", "}
                    <Link
                      href="/privacy"
                      className="underline hover:text-text-secondary transition-colors"
                    >
                      Privacy Policy
                    </Link>
                    {", and "}
                    <Link
                      href="/refund"
                      className="underline hover:text-text-secondary transition-colors"
                    >
                      Refund Policy
                    </Link>
                    .
                  </p>
                </div>

                <div className="mt-5 pt-4 border-t border-border text-center">
                  <p className="text-sm text-text-secondary">
                    Already have an account?{" "}
                    <Link
                      href={`/login?redirect=${encodeURIComponent(checkoutUrl)}`}
                      className="text-gold hover:text-gold-light font-medium transition-colors"
                    >
                      Sign in
                    </Link>
                  </p>
                </div>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

