                    {quiz?.title ?? "Part Quiz"}
                  </p>
                  {bestScore !== null && (
                    <p className={`text-xs ${bestScore >= (quiz?.passingScore ?? 70) ? "text-success" : "text-error"}`}>
                      Best score: {bestScore}%
                    </p>
