                            </Link>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          {/* Footer */}
          <div className="px-5 py-3 border-t border-border bg-surface-raised flex-shrink-0">
            <Link
              href="/parts"
              onClick={() => setIsOpen(false)}
              className="text-xs text-text-muted hover:text-gold transition-colors"
            >
              View full curriculum ΓåÆ
            </Link>
          </div>
        </div>
      </div>
    </>
  );
}

