"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { ChevronLeft, ChevronRight, Layers, Maximize2, X } from "lucide-react";
import { trackAssetOpened } from "@/app/actions/progress";
import type { SlideFile } from "@/lib/types";

/** Main slide image. Shows a spinner while loading, re-triggers on src change. */
function SlideImg({ src, alt, priority }: { src: string; alt: string; priority?: boolean }) {
  const [loaded, setLoaded] = useState(false);

  useEffect(() => { setLoaded(false); }, [src]);

  return (
    <>
      {!loaded && (
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="w-8 h-8 border-2 border-gold/30 border-t-gold rounded-full animate-spin" />
        </div>
      )}
      <img
        src={src}
        alt={alt}
        // eslint-disable-next-line react/no-unknown-property
        fetchPriority={priority ? "high" : "auto"}
        className={`max-w-full max-h-full object-contain transition-opacity duration-200 ${loaded ? "opacity-100" : "opacity-0"}`}
        onLoad={() => setLoaded(true)}
      />
    </>
  );
}

interface SlidesViewerProps {
  slides: SlideFile[];
  title?: string;
  type?: "presented" | "detailed";
  partNumber?: number;
  previewMode?: boolean;
}

export function SlidesViewer({ slides, title, type = "presented", partNumber, previewMode }: SlidesViewerProps) {
  const [current, setCurrent] = useState(0);
  const [fullscreen, setFullscreen] = useState(false);
  const stripRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const touchStartX = useRef<number | null>(null);

  const prev = useCallback(() => setCurrent((c) => Math.max(0, c - 1)), []);
  const next = useCallback(
    () => setCurrent((c) => Math.min(slides.length - 1, c + 1)),
    [slides.length]
  );

  const handleTouchStart = useCallback((e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
  }, []);

  const handleTouchEnd = useCallback((e: React.TouchEvent) => {
    if (touchStartX.current === null) return;
    const delta = e.changedTouches[0].clientX - touchStartX.current;
    touchStartX.current = null;
    if (Math.abs(delta) < 50) return; // ignore small taps
    if (delta < 0) next(); else prev();
  }, [next, prev]);

  useEffect(() => {
    // Keep CSS state in sync when native fullscreen is toggled (e.g. Esc key)
    const handler = () => {
      if (!document.fullscreenElement) setFullscreen(false);
    };
    document.addEventListener("fullscreenchange", handler);
    return () => document.removeEventListener("fullscreenchange", handler);
  }, []);

  const enterFullscreen = useCallback(async () => {
    // Set CSS overlay immediately ΓÇö reliable across all browsers
    setFullscreen(true);
    // Also attempt native fullscreen as an enhancement (browser chrome disappears)
    if (containerRef.current?.requestFullscreen) {
      try {
        await containerRef.current.requestFullscreen();
      } catch {
        // Native fullscreen denied ΓÇö CSS overlay is already shown, nothing to do
      }
    }
  }, []);

  const exitFullscreenMode = useCallback(() => {
    setFullscreen(false);
    if (document.fullscreenElement) {
      document.exitFullscreen().catch(() => {});
    }
  }, []);

  useEffect(() => {
    if (!partNumber || previewMode || !slides.length) return;
    trackAssetOpened(partNumber, "slides").catch(() => {});
    window.dispatchEvent(new CustomEvent("seerah:progressUpdate", { detail: { openedAssets: ["slides"] } }));
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const strip = stripRef.current;
    if (!strip) return;
    const thumb = strip.querySelectorAll("button")[current] as HTMLElement | undefined;
    thumb?.scrollIntoView({ behavior: "auto", block: "nearest", inline: "nearest" });
  }, [current]);

  useEffect(() => {
    if (!fullscreen) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === "ArrowLeft") prev();
      if (e.key === "ArrowRight") next();
      if (e.key === "Escape") exitFullscreenMode();
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [fullscreen, prev, next, exitFullscreenMode]);

  if (!slides.length) {
    return (
      <div className="aspect-video rounded-2xl border border-border bg-surface flex flex-col items-center justify-center gap-3">
        <div className="w-14 h-14 rounded-xl bg-gold/10 border border-gold/20 flex items-center justify-center">
          <Layers className="w-6 h-6 text-gold/50" />
        </div>
        <div className="text-center">
          <p className="text-text-secondary text-sm font-medium">No slides for this part</p>
          <p className="text-xs text-text-muted mt-1">
            {type === "presented" ? "Presented" : "Detailed"} slides will be available shortly
          </p>
        </div>
      </div>
    );
  }

  return (
    <div
      ref={containerRef}
      className={
        fullscreen
          ? "fixed inset-0 z-50 bg-black flex flex-col"
          : "rounded-2xl border border-border overflow-hidden bg-black flex flex-col"
      }
    >
      {/* Header */}
      <div className="flex items-center gap-3 px-4 py-3 bg-ink/80 border-b border-border/50 flex-shrink-0">
        <Layers className="w-4 h-4 text-gold flex-shrink-0" />
        <p className="text-sm text-text-secondary flex-1 truncate">
          {title || (type === "presented" ? "Presented Slides" : "Detailed Slides")}
        </p>
        <span className="text-xs text-text-muted tabular-nums">
          {current + 1} / {slides.length}
        </span>
        <button
          onClick={() => fullscreen ? exitFullscreenMode() : enterFullscreen()}
          className="min-h-[44px] min-w-[44px] flex items-center justify-center text-text-muted hover:text-text transition-colors -mr-2"
          aria-label={fullscreen ? "Exit fullscreen" : "Enter fullscreen"}
        >
          {fullscreen ? <X className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
        </button>
      </div>

      {/* Slide area ΓÇö swipe left/right to navigate on mobile */}
      <div
        className={`relative flex-1 bg-black ${!fullscreen ? "group cursor-zoom-in" : ""}`}
        style={{ minHeight: fullscreen ? undefined : "min(420px, 55vw)" }}
        onClick={!fullscreen ? () => enterFullscreen() : undefined}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
        title={!fullscreen ? "Tap for fullscreen ┬╖ Swipe to navigate" : undefined}
      >
        {/* Render current ┬▒2 slides; hidden ones are pre-loaded but invisible */}
        {slides.map((slide, idx) => {
          const distance = Math.abs(idx - current);
          if (distance > 2) return null;
          return (
            <div
              key={idx}
              className="absolute inset-0 flex items-center justify-center transition-opacity duration-150"
              style={{
                opacity: idx === current ? 1 : 0,
                pointerEvents: idx === current ? "auto" : "none",
                zIndex: idx === current ? 1 : 0,
              }}
            >
              <SlideImg src={slide.medium} alt={`Slide ${idx + 1}`} priority={idx === current} />
            </div>
          );
        })}

        {/* Fullscreen hint ΓÇö always visible at low opacity on mobile */}
        {!fullscreen && (
          <div className="absolute bottom-2 left-1/2 -translate-x-1/2 pointer-events-none">
            <div className="flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-black/60 border border-white/10 text-white/50 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity text-[10px] font-medium">
              <Maximize2 className="w-3 h-3" />
              <span>Tap ┬╖ Swipe to navigate</span>
            </div>
          </div>
        )}

        {/* Prev ΓÇö 44px */}
        <button
          onClick={(e) => { e.stopPropagation(); prev(); }}
          disabled={current === 0}
          className="absolute left-2 top-1/2 -translate-y-1/2 z-10 min-w-[44px] min-h-[44px] rounded-full bg-black/60 border border-white/15 flex items-center justify-center text-white/70 hover:text-white hover:border-white/40 disabled:opacity-20 transition-all"
          aria-label="Previous slide"
        >
          <ChevronLeft className="w-5 h-5" />
        </button>
        {/* Next ΓÇö 44px */}
        <button
          onClick={(e) => { e.stopPropagation(); next(); }}
          disabled={current === slides.length - 1}
          className="absolute right-2 top-1/2 -translate-y-1/2 z-10 min-w-[44px] min-h-[44px] rounded-full bg-black/60 border border-white/15 flex items-center justify-center text-white/70 hover:text-white hover:border-white/40 disabled:opacity-20 transition-all"
          aria-label="Next slide"
        >
          <ChevronRight className="w-5 h-5" />
        </button>
      </div>

      {/* Thumbnail strip ΓÇö fade hint at right edge indicates more content */}
      {slides.length > 1 && (
        <div className="relative bg-ink/80 border-t border-border/50 flex-shrink-0">
          {/* Fade overlay at right edge */}
          <div className="pointer-events-none absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-l from-ink/80 to-transparent z-10" aria-hidden />
        <div ref={stripRef} className="pl-4 py-3 flex gap-2 overflow-x-auto no-scrollbar">
          {slides.map((slide, i) => (
            <button
              key={i}
              onClick={() => setCurrent(i)}
              aria-label={`Go to slide ${i + 1}`}
              aria-current={i === current ? "true" : undefined}
              className={`flex-shrink-0 w-20 h-11 rounded border overflow-hidden transition-all ${
                i === current
                  ? "border-gold ring-1 ring-gold/30"
                  : "border-border/50 opacity-50 hover:opacity-100"
              }`}
            >
              <img src={slide.thumb} alt={`Slide ${i + 1}`} className="w-full h-full object-cover" />
            </button>
          ))}
          <div className="flex-shrink-0 w-8" aria-hidden />
        </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { BookOpen, Clock, Layers, ClipboardCheck, ArrowRight } from "lucide-react";
import { trackBriefingOpened, trackAssetOpened } from "@/app/actions/progress";
import { formatSeerahContent } from "@/lib/text-formatter";
import { PART_CONTENT } from "@/lib/part-content-data";
import { PARTS } from "@/lib/content";
import { ERA_MAP } from "@/lib/types";

const ASSET_META: Record<string, { label: string; subtitle: string }> = {
  briefing: {
    label: "LESSON BRIEFING",
    subtitle: "A structured written summary of this lesson. Best reviewed after watching the video.",
  },
  study_guide: {
    label: "STUDY GUIDE",
    subtitle: "A deeper review of key concepts, names, and events from this lesson.",
  },
};

/** Estimate reading time from raw HTML string. */
function estimateReadTime(html: string): string {
  const words = html.replace(/<[^>]+>/g, " ").trim().split(/\s+/).length;
  const minutes = Math.max(2, Math.round(words / 220));
  return `${minutes} min read`;
}

interface TextViewerProps {
  content: string;
  className?: string;
  partNumber?: number;
  /** "briefing" triggers briefingOpened tracking; any other value tracks as optional asset */
  assetId?: string;
  /** When true (free preview), skip all progress tracking ΓÇö user is not logged in */
  previewMode?: boolean;
  /** Whether a quiz is available for this lesson part */
  hasQuiz?: boolean;
  /** Callback to switch to the quiz mode from the parent tab controller */
  onSwitchToQuiz?: () => void;
}

export function TextViewer({
  content,
  className,
  partNumber,
  assetId,
  previewMode,
  hasQuiz,
  onSwitchToQuiz,
}: TextViewerProps) {
  const preRendered =
    partNumber && assetId === "briefing"
      ? (PART_CONTENT[partNumber]?.briefingHtml ?? null)
      : null;
  const html = preRendered ?? formatSeerahContent(content);
  const meta = assetId ? ASSET_META[assetId] : undefined;
  const readTime = estimateReadTime(html);

  // Look up part metadata for era label and lesson title
  const partData = partNumber ? PARTS.find((p) => p.partNumber === partNumber) : undefined;
  const eraLabel = partData ? (ERA_MAP[partData.era as keyof typeof ERA_MAP]?.label ?? "") : "";
  const totalParts = PARTS.length;

  // Reading progress (0ΓÇô100)
  const [readProgress, setReadProgress] = useState(0);
  const articleRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const el = articleRef.current;
    if (!el) return;

    const onScroll = () => {
      const rect = el.getBoundingClientRect();
      const windowH = window.innerHeight;
      // How far the user has scrolled through the article
      const scrolled = Math.max(0, windowH - rect.top);
      const total = el.offsetHeight;
      const pct = Math.min(100, Math.round((scrolled / total) * 100));
      setReadProgress(pct);
    };

    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll(); // initialise
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  useEffect(() => {
    if (!partNumber || previewMode) return;
    if (assetId === "briefing") {
      trackBriefingOpened(partNumber).catch(() => {});
      window.dispatchEvent(
        new CustomEvent("seerah:progressUpdate", { detail: { briefingOpened: true } })
      );
    } else if (assetId) {
      trackAssetOpened(partNumber, assetId).catch(() => {});
      window.dispatchEvent(
        new CustomEvent("seerah:progressUpdate", { detail: { openedAssets: [assetId] } })
      );
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className={`article-shell ${className ?? ""}`} ref={articleRef}>
      {/* Fixed reading progress bar ΓÇö sticks to viewport top as user scrolls through article.
          z-[60] places it above sticky headers; 2px height makes it unobtrusive.
          pointer-events-none ensures it never blocks clicks. */}
      {readProgress > 0 && (
        <div
          aria-hidden
          className="pointer-events-none"
          style={{ position: "fixed", top: 0, left: 0, right: 0, height: 2, zIndex: 60 }}
        >
          <div
            className="article-progress-fill"
            style={{ width: `${readProgress}%` }}
          />
        </div>
      )}

      <div className="article-container">

        {/* Thin reading progress bar ΓÇö top of article */}
        <div className="article-progress-track">
          <div
            className="article-progress-fill"
            style={{ width: `${readProgress}%` }}
          />
        </div>

        {/* Article header */}
        {meta && (
          <div className="article-header">
            <p className="article-label">{meta.label}</p>

            {/* Lesson title from content data */}
            {partData && (
              <h2
                className="article-title"
                style={{ hyphens: "none", overflowWrap: "normal", wordBreak: "normal" }}
              >
                {partData.title}
              </h2>
            )}
            {partData?.subtitle && (
              <p className="article-lesson-subtitle">{partData.subtitle}</p>
            )}

            {/* Metadata row ΓÇö Part X ┬╖ Era ┬╖ Read time */}
            <div className="article-meta-row">
              {partNumber && (
                <>
                  <span className="article-meta-item">
                    <Layers size={11} strokeWidth={2} />
                    Part {partNumber} of {totalParts}
                  </span>
                  <span className="article-meta-sep" aria-hidden>┬╖</span>
                </>
              )}
              {eraLabel && (
                <>
                  <span className="article-meta-item">{eraLabel}</span>
                  <span className="article-meta-sep" aria-hidden>┬╖</span>
                </>
              )}
              <span className="article-meta-item">
                <Clock size={11} strokeWidth={2} />
                {readTime}
              </span>
            </div>

            {/* What this document is */}
            <p className="article-subtitle">{meta.subtitle}</p>

            {/* Reading progress context */}
            <div className="article-progress-context">
              <div className="article-progress-context-bar">
                <div
                  className="article-progress-context-fill"
                  style={{ width: `${readProgress}%` }}
                />
              </div>
              <span className="article-progress-context-label">
                {readProgress < 5 ? "Start reading" : readProgress >= 95 ? "Completed" : `${readProgress}% through`}
              </span>
            </div>
          </div>
        )}

        {/* Divider */}
        {meta && <div className="article-divider" />}

        {/* Article body */}
        <div
          className="formatted-text"
          dangerouslySetInnerHTML={{ __html: html }}
        />

        {/* Bottom reading-complete prompt */}
        {meta && (
          <div className="article-end-marker">
            <div className="article-end-line" />
            <p className="article-end-label">
              <BookOpen size={11} strokeWidth={2} />
              End of {meta.label.toLowerCase().replace("lesson ", "")}
            </p>
          </div>
        )}

        {/* End-of-article CTA ΓÇö shown after reading a briefing or study guide */}
        {meta && (
          <div className="mt-8 flex flex-col items-center gap-3 text-center">
            {onSwitchToQuiz ? (
              <button
                type="button"
                onClick={onSwitchToQuiz}
                className="inline-flex items-center gap-2 px-6 py-3 min-h-[44px] bg-gold hover:bg-gold-light text-ink font-semibold rounded-xl text-sm transition-colors shadow-md shadow-gold/20"
              >
                <ClipboardCheck className="w-4 h-4" />
                Take the Quiz
              </button>
            ) : hasQuiz !== false && partNumber ? (
              <a
                href={`?mode=quiz`}
                className="inline-flex items-center gap-2 px-6 py-3 min-h-[44px] bg-gold hover:bg-gold-light text-ink font-semibold rounded-xl text-sm transition-colors shadow-md shadow-gold/20"
              >
                <ClipboardCheck className="w-4 h-4" />
                Take the Quiz
              </a>
            ) : (
              <a
                href="/seerah"
                className="inline-flex items-center gap-2 px-5 py-2.5 min-h-[44px] border border-border hover:border-gold/40 text-text-secondary hover:text-text rounded-xl text-sm font-medium transition-colors"
              >
                Continue Learning
                <ArrowRight className="w-4 h-4" />
              </a>
            )}
            <p className="text-[11px] text-text-muted/60">
              {onSwitchToQuiz || (hasQuiz !== false && partNumber)
                ? "Test your understanding of this lesson"
                : "Return to the lesson list"}
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useRef, useCallback, useEffect } from "react";
import { Play, Pause, Volume2, VolumeX, Maximize, RotateCcw, RotateCw } from "lucide-react";
import { trackVideoProgress } from "@/app/actions/progress";

// Report at these percent thresholds (once each per mount)
const REPORT_THRESHOLDS = [25, 50, 75, 85, 95, 100];

interface VideoPlayerProps {
  src?: string;
  title?: string;
  poster?: string;
  partNumber?: number;
  /** When true (free preview), skip progress tracking ΓÇö user is not logged in */
  previewMode?: boolean;
}

export function VideoPlayer({ src, title, poster, partNumber, previewMode }: VideoPlayerProps) {
  const videoRef   = useRef<HTMLVideoElement>(null);
  const reportedRef = useRef<Set<number>>(new Set());

  // Pause video when audio starts playing elsewhere on the page
  useEffect(() => {
    const handler = () => {
      if (videoRef.current && !videoRef.current.paused) {
        videoRef.current.pause();
      }
    };
    window.addEventListener("seerah:audioPlaying", handler);
    return () => window.removeEventListener("seerah:audioPlaying", handler);
  }, []);

  const [started,  setStarted]  = useState(false);
  const [playing,  setPlaying]  = useState(false);
  const [muted,    setMuted]    = useState(false);
  const [volume,   setVolume]   = useState(0.5);
  const [showVolumeSlider, setShowVolumeSlider] = useState(false);
  const [progress, setProgress] = useState(0);
  const [controlsVisible, setControlsVisible] = useState(false);
  const [videoError, setVideoError] = useState(false);
  const controlsTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const showControlsTemporarily = useCallback(() => {
    setControlsVisible(true);
    if (controlsTimerRef.current) clearTimeout(controlsTimerRef.current);
    controlsTimerRef.current = setTimeout(() => setControlsVisible(false), 3000);
  }, []);

  const handleVideoTap = useCallback(() => {
    if (!started) return; // pre-play overlay handles this
    showControlsTemporarily();
  }, [started, showControlsTemporarily]);

  if (!src) {
    return (
      <div className="aspect-video rounded-2xl bg-surface border border-border flex flex-col items-center justify-center gap-3">
        <div className="w-16 h-16 rounded-full bg-gold/10 border border-gold/20 flex items-center justify-center">
          <Play className="w-7 h-7 text-gold/60 ml-1" />
        </div>
        <div className="text-center">
          <p className="text-text-secondary text-sm font-medium">No video for this part</p>
          <p className="text-text-muted text-xs mt-1">This content will be available shortly</p>
        </div>
      </div>
    );
  }

  const togglePlay = () => {
    if (!videoRef.current) return;
    if (playing) {
      videoRef.current.pause();
    } else {
      videoRef.current.play();
      setStarted(true);
    }
    setPlaying(!playing);
  };

  const handleTimeUpdate = useCallback(() => {
    if (!videoRef.current) return;
    const pct = (videoRef.current.currentTime / videoRef.current.duration) * 100;
    const rounded = isNaN(pct) ? 0 : Math.round(pct);
    setProgress(rounded);

    // Report to server at each threshold (once per session)
    if (partNumber && !previewMode) {
      for (const threshold of REPORT_THRESHOLDS) {
        if (rounded >= threshold && !reportedRef.current.has(threshold)) {
          reportedRef.current.add(threshold);
          // Fire-and-forget ΓÇö don't block the UI
          trackVideoProgress(partNumber, rounded).catch(() => {});
        }
      }
    }
  }, [partNumber]);

  const handleSeek = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!videoRef.current) return;
    const duration = videoRef.current.duration;
    // duration is NaN until metadata loads and Infinity on live streams ΓÇö skip both
    if (!isFinite(duration) || duration <= 0) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const pct  = Math.min(1, Math.max(0, (e.clientX - rect.left) / rect.width));
    videoRef.current.currentTime = pct * duration;
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    if (muted) {
      // Unmute: restore volume (or set to 50% if it was 0)
      const newVolume = volume === 0 ? 0.5 : volume;
      videoRef.current.volume = newVolume;
      videoRef.current.muted = false;
      setVolume(newVolume);
      setMuted(false);
    } else {
      // Mute
      videoRef.current.muted = true;
      setMuted(true);
    }
  };

  const handleVolumeChange = (newVolume: number) => {
    if (!videoRef.current) return;
    const clampedVolume = Math.max(0, Math.min(1, newVolume));
    setVolume(clampedVolume);
    videoRef.current.volume = clampedVolume;
    if (clampedVolume === 0) {
      setMuted(true);
      videoRef.current.muted = true;
    } else if (muted) {
      setMuted(false);
      videoRef.current.muted = false;
    }
  };

  if (videoError) {
    return (
      <div className="aspect-video rounded-2xl bg-surface border border-border flex flex-col items-center justify-center gap-3 px-4 text-center">
        <div className="w-14 h-14 rounded-full bg-red-500/10 border border-red-500/20 flex items-center justify-center">
          <Play className="w-6 h-6 text-red-400/60 ml-0.5" />
        </div>
        <div>
          <p className="text-text-secondary text-sm font-medium">Video unavailable</p>
          <p className="text-text-muted text-xs mt-1">Try refreshing the page or check your connection</p>
        </div>
        <button
          onClick={() => setVideoError(false)}
          className="mt-1 px-4 py-2 rounded-lg bg-surface-raised border border-border text-sm text-text-secondary hover:text-text hover:border-gold/30 transition-colors min-h-[44px]"
        >
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="rounded-2xl overflow-hidden border border-border bg-black relative group">
      <video
        ref={videoRef}
        src={src}
        poster={poster}
        preload="none"
        playsInline
        className="w-full aspect-video"
        onClick={handleVideoTap}
        onTouchEnd={handleVideoTap}
        onLoadedMetadata={() => {
          if (videoRef.current) {
            videoRef.current.volume = volume;
          }
        }}
        onTimeUpdate={handleTimeUpdate}
        onError={() => setVideoError(true)}
        onEnded={() => {
          setPlaying(false);
          setStarted(false);
          if (partNumber && !previewMode && !reportedRef.current.has(100)) {
            reportedRef.current.add(100);
            trackVideoProgress(partNumber, 100).catch(() => {});
          }
        }}
        onPlay={() => { setPlaying(true); window.dispatchEvent(new CustomEvent("seerah:videoPlaying")); }}
        onPause={() => setPlaying(false)}
        title={title}
      />

      {/* Pre-play overlay */}
      {!started && (
        <button
          onClick={togglePlay}
          className="absolute inset-0 z-10 flex flex-col items-center justify-center gap-4 bg-black/30"
        >
          <div className="w-20 h-20 rounded-full bg-gold/20 border-2 border-gold/50 backdrop-blur-sm flex items-center justify-center hover:bg-gold/30 hover:scale-105 transition-all duration-200 shadow-2xl shadow-black/50">
            <Play className="w-9 h-9 text-gold ml-1.5" />
          </div>
          {title && (
            <p className="text-white/80 text-sm font-medium max-w-xs text-center px-4 drop-shadow">
              {title}
            </p>
          )}
        </button>
      )}

      {/* Controls ΓÇö visible on hover (desktop) or tap (mobile) */}
      <div
        className={`absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent p-4 transition-all duration-200 ${
          started ? (controlsVisible ? "opacity-100" : "opacity-0 group-hover:opacity-100") : "opacity-0"
        }`}
        onTouchStart={showControlsTemporarily}
        onMouseMove={showControlsTemporarily}
      >
        {/* Seek bar ΓÇö tall invisible hit area wraps the thin visual bar */}
        <div
          className="relative w-full h-8 flex items-center mb-1 cursor-pointer"
          onClick={handleSeek}
          aria-label="Video progress"
        >
          <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 h-1 bg-white/25 rounded-full">
            <div
              className="h-1 bg-gold rounded-full transition-all"
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>

        <div className="flex items-center gap-1">
          {/* Play/Pause ΓÇö 44px */}
          <button
            onClick={togglePlay}
            className="min-w-[44px] min-h-[44px] rounded-full bg-white/15 hover:bg-white/25 flex items-center justify-center transition-colors"
            aria-label={playing ? "Pause" : "Play"}
          >
            {playing
              ? <Pause className="w-5 h-5 text-white" />
              : <Play  className="w-5 h-5 text-white ml-0.5" />
            }
          </button>

          {/* Rewind 10s ΓÇö 44px */}
          <button
            onClick={() => { if (videoRef.current) videoRef.current.currentTime = Math.max(0, videoRef.current.currentTime - 10); }}
            className="relative min-w-[44px] min-h-[44px] flex items-center justify-center text-white/70 hover:text-white transition-colors"
            aria-label="Rewind 10 seconds"
          >
            <RotateCcw className="w-5 h-5" />
            <span className="absolute text-[7px] font-bold leading-none" aria-hidden>10</span>
          </button>

          {/* Forward 10s ΓÇö 44px */}
          <button
            onClick={() => { if (videoRef.current) videoRef.current.currentTime = Math.min(videoRef.current.duration || Infinity, videoRef.current.currentTime + 10); }}
            className="relative min-w-[44px] min-h-[44px] flex items-center justify-center text-white/70 hover:text-white transition-colors"
            aria-label="Forward 10 seconds"
          >
            <RotateCw className="w-5 h-5" />
            <span className="absolute text-[7px] font-bold leading-none" aria-hidden>10</span>
          </button>

          <div className="relative flex items-center gap-1">
            {/* Mute ΓÇö 44px */}
            <button
              onClick={() => setShowVolumeSlider(!showVolumeSlider)}
              onDoubleClick={toggleMute}
              className="min-w-[44px] min-h-[44px] flex items-center justify-center text-white/70 hover:text-white transition-colors"
              aria-label={muted || volume === 0 ? "Unmute" : "Mute"}
            >
              {muted || volume === 0 ? <VolumeX className="w-4 h-4" /> : <Volume2 className="w-4 h-4" />}
            </button>

            {/* Volume Slider - horizontal */}
            {showVolumeSlider && (
              <div className="flex items-center gap-2 bg-black/90 backdrop-blur-sm rounded-lg px-3 py-1">
                <input
                  type="range"
                  min="0"
                  max="100"
                  value={muted ? 0 : volume * 100}
                  onChange={(e) => handleVolumeChange(parseInt(e.target.value) / 100)}
                  className="w-20 h-1 appearance-none bg-white/25 rounded-full cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-gold [&::-webkit-slider-thumb]:cursor-pointer [&::-moz-range-thumb]:w-3 [&::-moz-range-thumb]:h-3 [&::-moz-range-thumb]:rounded-full [&::-moz-range-thumb]:bg-gold [&::-moz-range-thumb]:border-0 [&::-moz-range-thumb]:cursor-pointer"
                  style={{
                    background: `linear-gradient(to right, rgb(212, 175, 55) 0%, rgb(212, 175, 55) ${muted ? 0 : volume * 100}%, rgba(255, 255, 255, 0.25) ${muted ? 0 : volume * 100}%, rgba(255, 255, 255, 0.25) 100%)`
                  }}
                />
                <span className="text-white/70 text-xs font-medium w-8 text-right">{Math.round(muted ? 0 : volume * 100)}%</span>
              </div>
            )}
          </div>

          <div className="flex-1" />

          {/* Fullscreen ΓÇö 44px */}
          <button
            onClick={() => videoRef.current?.requestFullscreen()}
            className="min-w-[44px] min-h-[44px] flex items-center justify-center text-white/70 hover:text-white transition-colors"
            aria-label="Fullscreen"
          >
            <Maximize className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
}

