// Apply semantic inline formatting to a single fact line
function formatFactLine(text: string): string {
  let processed = text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

  processed = processed
    .replace(/\b(Muhammad|Prophet\s+Muhammad)\s*(∩╖║)?/gi, '<span class="text-amber-400 font-bold">$1 ∩╖║</span>')
