      {selectedPart && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4 backdrop-blur-sm"
          onClick={handleClose}
        >
          <div
            className="relative w-full max-w-4xl max-h-[90vh] bg-ink border border-border/60 rounded-2xl shadow-2xl flex flex-col overflow-hidden"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Gold top accent */}
            <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-gold/40 to-transparent" />

            {/* Modal Header */}
            <div className="flex items-center justify-between px-6 py-4 border-b border-border flex-shrink-0">
              <div>
                <p className="text-xs font-semibold uppercase tracking-widest text-gold mb-1">
                  Part {selectedPart.partNumber}
                </p>
                <h2 className="text-lg font-bold text-text">{selectedPart.title}</h2>
                {selectedPart.subtitle && (
                  <p className="text-sm text-text-secondary mt-0.5">{selectedPart.subtitle}</p>
                )}
              </div>
              <button
                onClick={handleClose}
                className="w-9 h-9 rounded-lg hover:bg-surface-raised flex items-center justify-center transition-colors flex-shrink-0"
              >
                <X className="w-4 h-4 text-text-muted" />
              </button>
            </div>

            {/* Modal Content */}
            <div className="flex-1 overflow-y-auto overscroll-contain">
              {resourceType === "statement-of-facts" ? (
                /* ΓöÇΓöÇ Facts ΓÇö same rendering as FactsViewer in lessons ΓöÇΓöÇ */
                <div className="p-6">
                  {(() => {
                    const text = getFactsText(selectedPart.partNumber);
                    if (!text) return <p className="text-text-muted text-sm">No facts available.</p>;
                    const facts = text.split("\n").map(l => l.trim()).filter(Boolean);
                    return (
                      <ol className="space-y-3">
                        {facts.map((fact, i) => (
                          <li key={i} className="flex gap-4 items-baseline">
                            <span className="flex-shrink-0 w-7 text-right text-xs font-semibold text-gold/50 tabular-nums mt-[2px]">
                              {i + 1}
                            </span>
                            <span
                              className="text-base text-zinc-300 leading-relaxed"
                              dangerouslySetInnerHTML={{ __html: formatFactLine(fact) }}
                            />
                          </li>
                        ))}
                      </ol>
                    );
                  })()}
                </div>
              ) : (
                /* ΓöÇΓöÇ Briefing ΓÇö same article-shell rendering as TextViewer in lessons ΓöÇΓöÇ */
                <div className="article-shell p-6">
                  <div className="article-container">
                    <div
                      className="formatted-text"
                      dangerouslySetInnerHTML={{
                        __html: getHtml(selectedPart.partNumber) ?? "<p class='seerah-p text-text-muted'>Content not available.</p>",
                      }}
                    />
                  </div>
                </div>
              )}
            </div>

            {/* Modal Footer */}
            <div className="flex items-center justify-end px-6 py-4 border-t border-border flex-shrink-0">
              <button
                onClick={handleClose}
                className="px-5 py-2 rounded-lg bg-gold text-ink hover:bg-gold-light text-sm font-semibold transition-colors"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <ResourcePageClient showStatusFilter filterByStatus={filterByStatus}>
          {(parts) => (
            <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 sm:gap-4">
              {parts.map((part) => {
                const isRead = localProgressMap[part.partNumber] || false;
                return (
                  <div
                    key={part.id}
                    onClick={() => handleOpenContent(part)}
                    className="group cursor-pointer rounded-xl border border-zinc-800 bg-zinc-900/50 hover:bg-zinc-900 hover:border-amber-500/30 transition-all overflow-hidden"
                  >
                    <div
                      className="aspect-video relative flex items-center justify-center overflow-hidden"
                      style={eraGradient(part.era)}
                    >
                      {thumbnails[part.partNumber] && (
                        <img
                          src={thumbnails[part.partNumber]}
                          alt=""
                          loading="lazy"
                          className="absolute inset-0 w-full h-full object-cover opacity-0 transition-opacity duration-500"
                          onLoad={(e) => { (e.currentTarget as HTMLImageElement).style.opacity = "1"; }}
                          onError={(e) => { (e.currentTarget as HTMLImageElement).style.display = "none"; }}
                        />
                      )}
                      <span className="absolute inset-0 flex items-center justify-center opacity-[0.12] text-[5rem] font-black text-white select-none pointer-events-none leading-none">
                        {part.partNumber}
                      </span>
                      <span className="absolute bottom-8 left-0 right-0 text-center text-[10px] font-semibold uppercase tracking-widest text-white/40 select-none">
                        {ERA_MAP[part.era as keyof typeof ERA_MAP]?.label ?? part.era}
                      </span>
                      {isRead && (
                        <div className="absolute top-2 right-2 w-6 h-6 rounded-full bg-green-500/30 border border-green-500/50 flex items-center justify-center">
                          <CheckCircle2 className="w-4 h-4 text-green-400" />
                        </div>
                      )}
                      <div className="relative z-10 w-14 h-14 rounded-full bg-black/40 border border-white/25 flex items-center justify-center group-hover:bg-white/20 group-hover:border-white/40 transition-all">
                        <IconComponent className="w-6 h-6 text-white" />
                      </div>
                    </div>
                    <div className="p-4">
                      <div className="flex items-center gap-2 mb-2">
                        <span className="text-xs font-medium text-amber-500">Part {part.partNumber}</span>
                        {isRead && (
                          <span className="px-2 py-0.5 bg-green-500/10 border border-green-500/20 text-green-400 text-xs font-medium rounded">
                            Read
                          </span>
                        )}
                      </div>
                      <h3 className="text-sm font-semibold text-white mb-1 line-clamp-2 group-hover:text-amber-400 transition-colors">
                        {part.title}
                      </h3>
                      {part.subtitle && (
                        <p className="text-xs text-zinc-500 line-clamp-1 mb-2">{part.subtitle}</p>
                      )}
                      {part.duration && (
                        <div className="flex items-center gap-1 text-xs text-zinc-500">
                          <Clock className="w-3 h-3" />
                          ~{part.duration} read
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </ResourcePageClient>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { PARTS } from "@/lib/content";
import { eraGradient } from "./era-gradient";
import { ResourcePageClient } from "./resource-page-client";
import { Video, Play, CheckCircle2, Clock, X } from "lucide-react";
import { VideoPlayer } from "@/components/part/video-player";
import { getCachedResource, setCachedResource, prefetchResource } from "@/lib/resource-cache";

interface VideoResourceContentProps {
  progressMap: Record<number, { videoWatchPercent: number; videoCompleted: boolean }>;
  completedCount: number;
  inProgressCount: number;
  continueWatching?: { partNumber: number; videoWatchPercent: number };
  thumbnails?: Record<number, string>;
}

export function VideoResourceContent({
  progressMap,
  completedCount,
  inProgressCount,
  continueWatching,
  thumbnails = {},
}: VideoResourceContentProps) {
  const [mounted, setMounted] = useState(false);
  const [selectedPart, setSelectedPart] = useState<{
    partNumber: number;
    title: string;
    subtitle?: string;
    id: string;
  } | null>(null);
  const [videoUrl, setVideoUrl]           = useState<string>("");
  const [isLoadingVideo, setIsLoadingVideo] = useState(false);

  // Focus management for video modal
  const prevFocusRef = useRef<Element | null>(null);
  const modalRef     = useRef<HTMLDivElement>(null);

  const totalVideos    = PARTS.length;
  const notStartedCount = totalVideos - completedCount - inProgressCount;

  useEffect(() => { setMounted(true); }, []);

  // Lock body scroll when modal is open
  useEffect(() => {
    if (!selectedPart) return;
    const prev = document.body.style.overflow;
    document.body.style.overflow = "hidden";
    return () => { document.body.style.overflow = prev; };
  }, [selectedPart]);

  const filterByStatus = (part: any, status: string) => {
    const p = progressMap[part.partNumber];
    if (status === "completed")  return p?.videoCompleted || false;
    if (status === "in-progress") return !!(p && p.videoWatchPercent > 0 && !p.videoCompleted);
    if (status === "not-started") return !p || p.videoWatchPercent === 0;
    return true;
  };

  const handlePrefetch = useCallback((partNumber: number) => {
    prefetchResource("video", partNumber.toString());
  }, []);

  const handleOpenVideo = async (part: typeof PARTS[0]) => {
    setSelectedPart({ partNumber: part.partNumber, title: part.title, subtitle: part.subtitle, id: part.id });

    const cacheKey = `video-${part.partNumber}`;
    const cached = getCachedResource<{ videoUrl: string }>(cacheKey);
    if (cached?.videoUrl) { setVideoUrl(cached.videoUrl); return; }

    setIsLoadingVideo(true);
    try {
      const res  = await fetch(`/api/part/${part.partNumber}/assets`);
      if (!res.ok) throw new Error("Failed to fetch video");
      const data = await res.json();
      setVideoUrl(data.videoUrl || "");
      if (data.videoUrl) setCachedResource(cacheKey, data);
    } catch {
      setVideoUrl("");
    } finally {
      setIsLoadingVideo(false);
    }
  };

  const handleClose = useCallback(() => {
    setSelectedPart(null);
    setVideoUrl("");
  }, []);

  // Store previously focused element when modal opens; restore on close
  useEffect(() => {
    if (selectedPart) {
      prevFocusRef.current = document.activeElement;
      // Move focus to close button after paint so the DOM is ready
      requestAnimationFrame(() => {
        modalRef.current?.querySelector<HTMLElement>('[aria-label="Close video"]')?.focus();
      });
    } else if (prevFocusRef.current instanceof HTMLElement) {
      prevFocusRef.current.focus();
      prevFocusRef.current = null;
    }
  }, [selectedPart]);

  // Focus trap + Escape key while modal is open ΓÇö listener exists only during open state
  useEffect(() => {
    if (!selectedPart || !modalRef.current) return;
    const modal = modalRef.current;
    const FOCUSABLE = 'a[href], button:not([disabled]), input, select, textarea, [tabindex]:not([tabindex="-1"])';

    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        handleClose();
        return;
      }
      if (e.key !== "Tab") return;
      const focusable = Array.from(modal.querySelectorAll<HTMLElement>(FOCUSABLE));
      if (!focusable.length) return;
      const first = focusable[0];
      const last  = focusable[focusable.length - 1];
      if (e.shiftKey && document.activeElement === first) {
        e.preventDefault();
        last.focus();
      } else if (!e.shiftKey && document.activeElement === last) {
        e.preventDefault();
        first.focus();
      }
    };

    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, [selectedPart, handleClose]);

  const continueWatchingPart = continueWatching
    ? PARTS.find((p) => p.partNumber === continueWatching.partNumber)
    : null;

  // Stats config ΓÇö meaningful stats brighter, reference stats quieter
  const stats = [
    {
      label: "Total",
      value: totalVideos,
      color: "text-zinc-400",
      dim: true,
    },
    {
      label: "Completed",
      value: completedCount,
      color: completedCount > 0 ? "text-green-400" : "text-zinc-500",
      dim: false,
    },
    {
      label: "In Progress",
      value: inProgressCount,
      color: inProgressCount > 0 ? "text-amber-400" : "text-zinc-500",
      dim: false,
    },
    {
      label: "Not Started",
      value: notStartedCount,
      color: "text-zinc-500",
      dim: true,
    },
  ];

  return (
    <div className="min-h-screen bg-ink">

      {/* ΓöÇΓöÇ Hero Section ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="border-b border-zinc-800 bg-gradient-to-b from-zinc-900 to-ink">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-5 sm:py-8">

          {/* Title row ΓÇö compact on mobile */}
          <div className="flex items-center gap-3 mb-4">
            <div className="w-10 h-10 sm:w-14 sm:h-14 rounded-xl sm:rounded-2xl bg-amber-500/10 border border-amber-500/20 flex items-center justify-center flex-shrink-0">
              <Video className="w-5 h-5 sm:w-7 sm:h-7 text-amber-500" />
            </div>
            <div className="min-w-0">
              <h1 className="text-xl sm:text-3xl font-bold text-white leading-tight">Video Lessons</h1>
              <p className="text-zinc-500 text-xs sm:text-sm mt-0.5 leading-snug">
                All {totalVideos} guided lessons from the Seerah Masterclass
              </p>
            </div>
          </div>

          {/* Subtle progress context */}
          {completedCount > 0 && (
            <p className="text-xs text-zinc-600 mb-3">
              {completedCount} of {totalVideos} video lessons completed ┬╖ continue building your Seerah timeline
            </p>
          )}

          {/* Stats grid ΓÇö differentiated hierarchy */}
          <div className="grid grid-cols-4 gap-2 sm:gap-3">
            {stats.map((s) => (
              <div
                key={s.label}
                className={`px-2.5 py-3 sm:px-4 sm:py-4 rounded-xl border flex flex-col ${
                  s.dim
                    ? "bg-zinc-900/25 border-zinc-800/40"
                    : "bg-zinc-900/65 border-zinc-700/50"
                }`}
              >
                {/* Label ΓÇö fixed min-height keeps numbers baseline-aligned across all cards */}
                <p className={`text-[10px] font-semibold uppercase leading-tight min-h-[24px] flex items-start ${
                  s.dim
                    ? "tracking-[0.12em] text-zinc-600"
                    : "tracking-[0.12em] text-zinc-400"
                }`}
                  style={{ letterSpacing: "0.11em" }}
                >
                  {s.label}
                </p>
                {/* Number ΓÇö premium typographic treatment */}
                <p className={`text-[1.75rem] sm:text-[2.25rem] font-bold leading-none tracking-tight tabular-nums mt-2 ${s.color}`}>
                  {s.value}
                </p>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ΓöÇΓöÇ Main content ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-5 sm:py-8">

        {/* Continue Watching ΓÇö elevated as primary CTA */}
        {mounted && continueWatchingPart && (
          <div className="mb-5 rounded-2xl bg-gold/6 border border-gold/22 overflow-hidden">
            <div className="px-4 pt-3 pb-1.5">
              <p className="text-[10px] font-bold uppercase tracking-widest text-gold/80">Continue Watching</p>
            </div>
            <button
              type="button"
              onClick={() => handleOpenVideo(continueWatchingPart)}
              onMouseEnter={() => handlePrefetch(continueWatchingPart.partNumber)}
              className="group w-full text-left cursor-pointer px-4 pb-3"
              aria-label={`Resume Part ${continueWatchingPart.partNumber}: ${continueWatchingPart.title}`}
            >
              <div className="flex items-center gap-3 sm:gap-5">
                {/* Thumbnail */}
                <div
                  className="relative flex-shrink-0 w-28 sm:w-44 rounded-xl overflow-hidden"
                  style={{ ...eraGradient(continueWatchingPart.era), aspectRatio: "16/9" }}
                >
                  {thumbnails[continueWatchingPart.partNumber] ? (
                    <img
                      src={thumbnails[continueWatchingPart.partNumber]}
                      alt=""
                      className="absolute inset-0 w-full h-full object-cover"
                    />
                  ) : (
                    <span className="absolute inset-0 flex items-center justify-center opacity-10 text-5xl font-black text-white select-none">
                      {continueWatchingPart.partNumber}
                    </span>
                  )}
                  {/* Play overlay */}
                  <div className="absolute inset-0 flex items-center justify-center bg-black/20 group-hover:bg-black/30 transition-colors">
                    <div className="w-9 h-9 rounded-full bg-black/50 border border-white/30 flex items-center justify-center">
                      <Play className="w-4 h-4 text-white ml-0.5" />
                    </div>
                  </div>
                  {/* Progress bar */}
                  {continueWatching && (
                    <div className="absolute bottom-0 left-0 right-0 h-1 bg-black/40">
                      <div className="h-full bg-gold" style={{ width: `${continueWatching.videoWatchPercent}%` }} />
                    </div>
                  )}
                </div>

                {/* Info */}
                <div className="flex-1 min-w-0">
                  <p className="text-[11px] text-gold/80 font-medium mb-0.5">
                    Part {continueWatchingPart.partNumber}
                  </p>
                  <h3 className="text-sm sm:text-base font-semibold text-text group-hover:text-gold transition-colors line-clamp-2 leading-snug">
                    {continueWatchingPart.title}
                  </h3>
                  {continueWatching && (
                    <p className="text-xs text-zinc-500 mt-1">{continueWatching.videoWatchPercent}% watched</p>
                  )}
                </div>

                {/* Resume ΓÇö 44px */}
                <div className="flex-shrink-0 inline-flex items-center justify-center min-h-[44px] px-4 sm:px-5 rounded-xl bg-gold text-ink text-sm font-bold group-hover:bg-gold/90 transition-colors shadow-sm shadow-gold/20">
                  Resume
                </div>
              </div>
            </button>
          </div>
        )}

        {/* Filters + Video Grid */}
        <ResourcePageClient
          showStatusFilter
          filterByStatus={filterByStatus}
        >
          {(parts) => (
            <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 sm:gap-4">
              {mounted && parts.map((part) => {
                const progress    = progressMap[part.partNumber];
                const watchPct    = progress?.videoWatchPercent || 0;
                const isCompleted = progress?.videoCompleted || watchPct >= 85;

                return (
                  <div
                    key={part.id}
                    onClick={() => handleOpenVideo(part)}
                    onMouseEnter={() => handlePrefetch(part.partNumber)}
                    className="group cursor-pointer rounded-xl border border-zinc-800 bg-zinc-900/50 hover:bg-zinc-900 hover:border-amber-500/25 transition-all overflow-hidden"
                  >
                    {/* Thumbnail */}
                    <div
                      className="aspect-video relative overflow-hidden"
                      style={eraGradient(part.era)}
                    >
                      {thumbnails[part.partNumber] && (
                        <img
                          src={thumbnails[part.partNumber]}
                          alt=""
                          loading="lazy"
                          className="absolute inset-0 w-full h-full object-cover opacity-0 transition-opacity duration-500"
                          onLoad={(e) => { (e.currentTarget as HTMLImageElement).style.opacity = "1"; }}
                          onError={(e) => { (e.currentTarget as HTMLImageElement).style.display = "none"; }}
                        />
                      )}

                      {/* Bottom gradient ΓÇö keeps text/controls readable */}
                      <div className="absolute inset-x-0 bottom-0 h-12 bg-gradient-to-t from-black/70 to-transparent pointer-events-none" />

                      {/* Status badge ΓÇö top-right, doesn't cover title area */}
                      {isCompleted && (
                        <div className="absolute top-1.5 right-1.5 w-5 h-5 rounded-full bg-black/50 border border-gold/40 flex items-center justify-center z-10">
                          <CheckCircle2 className="w-3 h-3 text-gold" />
                        </div>
                      )}
                      {!isCompleted && watchPct > 0 && (
                        <div className="absolute top-1.5 right-1.5 px-1.5 py-0.5 rounded bg-black/70 border border-white/15 text-white text-[10px] font-medium z-10">
                          {watchPct}%
                        </div>
                      )}

                      {/* Play button ΓÇö centered, safe zone */}
                      <div className="absolute inset-0 flex items-center justify-center z-10">
                        <div className="w-9 h-9 rounded-full bg-black/45 border border-white/25 flex items-center justify-center group-hover:bg-white/20 group-hover:border-white/40 transition-all">
                          <Play className="w-4 h-4 text-white ml-0.5" />
                        </div>
                      </div>

                      {/* Part number ΓÇö bottom-left, inside gradient safe zone */}
                      <span className="absolute bottom-1.5 left-2 text-[10px] font-bold text-white/60 z-10">
                        {part.partNumber}
                      </span>

                      {/* Progress bar */}
                      {watchPct > 0 && (
                        <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-black/30 z-10">
                          <div className="h-full bg-gold/80" style={{ width: `${watchPct}%` }} />
                        </div>
                      )}
                    </div>

                    {/* Info */}
                    <div className="p-2.5 sm:p-3">
                      <div className="flex items-center gap-1.5 mb-1">
                        {isCompleted && (
                          <span className="px-1.5 py-0.5 bg-green-500/10 border border-green-500/15 text-green-400 text-[10px] font-medium rounded">
                            Done
                          </span>
                        )}
                        {!isCompleted && watchPct > 0 && (
                          <span className="flex items-center gap-0.5 text-[10px] text-zinc-500 ml-auto">
                            <Clock className="w-2.5 h-2.5" />
                            {part.duration}
                          </span>
                        )}
                      </div>
                      <h3 className="text-xs sm:text-sm font-semibold text-white line-clamp-2 group-hover:text-amber-400 transition-colors leading-snug">
                        {part.title}
                      </h3>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </ResourcePageClient>
      </div>

      {/* ΓöÇΓöÇ Video Modal ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      {mounted && selectedPart && (
        <div
          className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/90 sm:p-4 backdrop-blur-sm"
          onClick={handleClose}
        >
          <div
            ref={modalRef}
            role="dialog"
            aria-modal="true"
            aria-labelledby="video-modal-title"
            className="relative w-full max-w-5xl sm:max-h-[90vh] bg-surface border border-gold/15 sm:rounded-2xl shadow-2xl flex flex-col overflow-hidden"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Gold top line */}
            <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-gold/30 to-transparent" />

            {/* Modal Header */}
            <div className="flex items-center justify-between px-4 py-3 sm:p-5 border-b border-border flex-shrink-0">
              <div className="min-w-0 flex-1 pr-3">
                <div className="flex items-center gap-1.5 mb-0.5">
                  <Video className="w-3.5 h-3.5 text-gold flex-shrink-0" />
                  <span className="text-xs font-medium text-gold">Part {selectedPart.partNumber}</span>
                </div>
                <h2 id="video-modal-title" className="text-base sm:text-xl font-bold text-text line-clamp-2 leading-snug">
                  {selectedPart.title}
                </h2>
              </div>
              <button
                onClick={handleClose}
                className="min-w-[44px] min-h-[44px] rounded-lg hover:bg-surface-raised flex items-center justify-center transition-colors flex-shrink-0"
                aria-label="Close video"
              >
                <X className="w-5 h-5 text-text-muted" />
              </button>
            </div>

            {/* Modal Content ΓÇö capped at 55vh on desktop to prevent overflow on short screens */}
            <div className="flex-1 overflow-y-auto bg-black p-3 sm:p-5 sm:max-h-[55vh]">
              {isLoadingVideo ? (
                <div className="aspect-video flex items-center justify-center">
                  <div className="w-8 h-8 border-2 border-gold/30 border-t-gold rounded-full animate-spin" />
                </div>
              ) : (
                <VideoPlayer
                  src={videoUrl}
                  partNumber={selectedPart.partNumber}
                  title={selectedPart.title}
                />
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import rawFacts from "@/lib/prophet-facts.json";
import { useWidgetCycle, WIDGET_FADE_MS } from "./widget-cycle-context";

interface Fact {
  id: number;
  clean_fact: string;
  category: string;
  reference: string;
}

const FACTS: Fact[] = (rawFacts as Array<{
  id: number;
  clean_fact: string;
  category: string;
  reference: string;
}>).map(({ id, clean_fact, category, reference }) => ({
  id,
  clean_fact,
  category,
  reference,
}));

function pickRandom(exclude?: number): Fact {
  let f: Fact;
  do {
    f = FACTS[Math.floor(Math.random() * FACTS.length)];
  } while (FACTS.length > 1 && f.id === exclude);
  return f;
}

export function DidYouKnowWidget() {
  const { visible } = useWidgetCycle();
  // Start with index 0 so server and client render the same text (avoids hydration mismatch).
  // Randomize immediately after mount, then again on each cycle.
  const [fact, setFact] = useState<Fact>(FACTS[0]);

  useEffect(() => {
    setFact(pickRandom());
  }, []);

  // Swap content at the midpoint of the fade-out (while invisible)
  useEffect(() => {
    if (!visible) {
      const t = setTimeout(() => {
        setFact((prev) => pickRandom(prev.id));
      }, WIDGET_FADE_MS / 2);
      return () => clearTimeout(t);
    }
  }, [visible]);

  const shortRef = fact.reference
    .replace("Sahih al-Bukhari and Sahih Muslim", "Bukhari & Muslim")
    .replace("Sahih al-Bukhari", "Bukhari")
    .replace("Sahih Muslim", "Muslim");

  return (
    <div className="mx-3 mb-3 mt-2" role="region" aria-label="Did You Know">
      <div className="rounded-xl border border-gold/30 bg-[#1A1409] p-4 overflow-hidden relative">
        <div className="absolute left-0 top-4 bottom-4 w-[2px] rounded-full bg-gold/50" />

        <div className="pl-3.5">
          <div className="flex items-center gap-2 mb-2.5">
            <span className="text-gold-light text-sm leading-none">Γ£ª</span>
            <span className="text-[11px] font-bold text-gold-light uppercase tracking-widest">Did You Know?</span>
          </div>

          <div style={{ opacity: visible ? 1 : 0, transition: `opacity ${WIDGET_FADE_MS}ms ease-in-out` }}>
            <p className="text-xs text-[#E8E4F0] leading-relaxed">{fact.clean_fact}</p>
            <div className="flex items-center gap-1.5 mt-2.5 flex-wrap">
              <span className="inline-block px-2 py-0.5 rounded text-[10px] font-semibold bg-gold/20 text-gold border border-gold/30 leading-none">
                {fact.category}
              </span>
              <span className="text-[10px] text-[#9E9AAC]">┬╖ {shortRef}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

