      {/* ΓöÇΓöÇ Overlay ΓÇö z-[55] covers sticky tab bar (z-50) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      {mobileOpen && (
        <div
          className="lg:hidden fixed inset-0 bg-black/60 z-[55] backdrop-blur-[2px]"
          onClick={closeDrawer}
