      {/* ΓöÇΓöÇ Unified sidebar ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <aside
        id="mobile-drawer"
        ref={drawerRef}
        role="dialog"
        aria-modal="true"
        aria-label="Account menu"
        className={clsx(
          "fixed top-0 left-0 bottom-0 bg-surface border-r border-border flex flex-col transition-transform duration-300",
          // Desktop: sticky, always visible, collapsible width
          "lg:sticky lg:top-0 lg:h-screen lg:translate-x-0 lg:z-[40]",
          // Mobile: off-canvas drawer ΓÇö z-[65] sits above overlay (z-[55])
          "z-[65]",
          mobileOpen ? "translate-x-0" : "-translate-x-full lg:translate-x-0",
          // Width: on desktop use collapse state; on mobile use responsive vw cap
          collapsed
            ? "lg:w-16"
            : "lg:w-64 w-[min(320px,88vw)]"
        )}
      >
        {/* Desktop collapsed icon bar */}
        {collapsed && (
          <div className="hidden lg:flex flex-col items-center gap-2 py-3 border-b border-border">
            <Link href="/my-courses" aria-label="Complete Seerah">
              <Image
                src="/images/logodashboard.png"
                alt="Complete Seerah"
                width={32}
                height={32}
                className="w-8 h-8 rounded-lg"
                priority
              />
            </Link>
            <button
              onClick={() => setCollapsed(false)}
              className="w-8 h-8 rounded-lg bg-surface-raised hover:bg-surface-high flex items-center justify-center text-text-muted hover:text-text transition-all"
              aria-label="Expand sidebar"
              title="Expand sidebar"
            >
              <PanelLeftOpen className="w-4 h-4" />
            </button>
          </div>
        )}

        {/* Render mobile drawer content on mobile, desktop content on desktop */}
        <div className="lg:hidden flex flex-col flex-1 min-h-0">
          {mobileDrawerContent}
        </div>
        <div className="hidden lg:flex flex-col flex-1 min-h-0">
          {desktopContent}
        </div>
      </aside>
    </>
  );
}

