/**
 * Shared text formatting utility for Seerah content
 * Provides semantic highlighting and beautiful formatting for:
 * - Briefings
 * - Study Guides
 * - Reports
 * - Facts
 */

// Helper function to escape HTML
function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

// Apply inline markdown (bold, italic) and real markdown links.
// Must run AFTER HTML-escaping so we don't accidentally break tags.
function applyInlineFormatting(text: string): string {
  // Step 1 ΓÇö escape HTML
  let processed = text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

  // Step 2 ΓÇö real Markdown links [text](url)
  // External URLs open in new tab; internal relative paths navigate within the app.
  // Must come before bold/italic so URLs with * or _ are not corrupted.
  processed = processed.replace(
    /\[([^\]]+)\]\(([^)]+)\)/g,
    (_, linkText, url) => {
      const isExternal = /^https?:\/\//.test(url);
      return isExternal
        ? `<a href="${url}" target="_blank" rel="noopener noreferrer">${linkText}</a>`
        : `<a href="${url}">${linkText}</a>`;
    }
  );

  // Step 3 ΓÇö inline markdown (order matters: *** before ** before *)
  processed = processed
    // ***bold italic***
    .replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
    // **bold**
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    // *italic*  (not preceded/followed by another *)
    .replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, '<em>$1</em>')
    // __bold__ (alternate syntax)
    .replace(/__(.+?)__/g, '<strong>$1</strong>')
    // _italic_ (alternate syntax)
    .replace(/(?<!_)_(?!_)(.+?)(?<!_)_(?!_)/g, '<em>$1</em>');

  // Step 4 ΓÇö Prophet ∩╖║ references ΓÇö gold, semibold, NOT underlined, NOT a link.
  // Longest patterns first to prevent partial overlaps.
  // "Prophet Muhammad" is always matched (unambiguous proper name);
  // bare "the Prophet" and "Messenger" only when the ∩╖║ symbol is present.
  processed = processed.replace(
    /(Messenger\s+of\s+Allah\s+∩╖║|Prophet\s+Muhammad(?:\s+∩╖║)?|the\s+Prophet\s+∩╖║|Messenger\s+∩╖║)/g,
    '<span class="seerah-prophet">$1</span>'
  );

  // Step 5 ΓÇö Qur'an / Revelation terms ΓÇö semibold, inherits colour, NOT a link.
  // "revelation/Revelation" included: in Seerah content it always means waß╕Ñy,
  // never generic disclosure. All other terms are specific transliterations.
  processed = processed.replace(
    /(Qur[''╩╛]?[a─ü]n|[Rr]evelation|waß╕Ñy|Jibr─½l|S┼½rah|─üyah|al-Isr─ü[''╩╛]|Mi╩┐r─üj)/g,
    '<span class="seerah-revelation">$1</span>'
  );

  // Step 6 ΓÇö Core Islamic concepts ΓÇö slightly brightened semibold, NOT a link.
  // Both capitalisation variants kept where the term appears in various styles.
  processed = processed.replace(
    /(tawß╕Ñ─½d|shirk|─½m─ün|da╩┐wah|[Hh]ijrah|Sunnah|ß╣úal─üh|[Hh]ajj|taw─üf|Ka╩┐bah)/g,
    '<span class="seerah-concept">$1</span>'
  );

  // Step 7 ΓÇö Quoted text ΓÇö muted italic
  processed = processed.replace(
    /&quot;([^&]+?)&quot;/g,
    '<span class="seerah-quote">&quot;$1&quot;</span>'
  );

  return processed;
}

/**
 * Format Seerah text content with semantic highlighting and beautiful typography
 * @param text - Raw text content
 * @returns HTML string with formatted content
 */
export function formatSeerahContent(text: string): string {
  if (!text) return "";

  const lines = text.split('\n');
  const formatted: string[] = [];
  let inList = false;
  let inNestedList = false;
  let inTable = false;
  let firstContentSeen = false;

  const closeNestedList = () => {
    if (inNestedList) { formatted.push('</ul>'); inNestedList = false; }
  };
  const closeList = () => {
    closeNestedList();
    if (inList) { formatted.push('</ul>'); inList = false; }
  };
  const closeTable = () => {
    if (inTable) { formatted.push('</tbody></table>'); inTable = false; }
  };

  // Returns true if a line looks like a section heading.
  // Handles mixed-case headings like "Location and Boundaries" or "Hub of Exchange".
  // Deliberately conservative: prose lead-ins that happen to be title-cased should
  // stay as paragraphs; only clean short noun-phrase titles qualify.
  const isSectionHeading = (ln: string): boolean => {
    if (ln.length >= 80 || ln.match(/[.!?:]$/)) return false;
    // Commas indicate a clause or complex phrase, not a clean title
    if (ln.includes(',')) return false;
    const words = ln.split(/\s+/);
    // Tighten word count: real section titles are short (2ΓÇô7 words)
    if (words.length < 2 || words.length > 7) return false;
    // First word and last word must start with uppercase
    if (!/^[A-Z]/.test(words[0]) || !/^[A-Z]/.test(words[words.length - 1])) return false;
    // At least 70% of words must start with uppercase
    const capCount = words.filter(w => /^[A-Z]/.test(w)).length;
    return capCount / words.length >= 0.7;
  };

  // Extra state for pipe-table header tracking
  let pipeTableHeaderOpen = false; // true between <thead> and </thead>

  const closePipeTableHeader = () => {
    if (pipeTableHeaderOpen) {
      formatted.push('</tr></thead><tbody>');
      pipeTableHeaderOpen = false;
    }
  };
  const closeTableFull = () => {
    closePipeTableHeader();
    if (inTable) { formatted.push('</tbody></table>'); inTable = false; }
  };
  // Override the earlier closeTable with the full version
  // (reassign via wrapper ΓÇö closeTable is already declared above)

  for (let i = 0; i < lines.length; i++) {
    // Keep raw line (minus CR) to preserve leading whitespace for indent detection
    // and to preserve trailing tabs that trim() would remove.
    const rawLine = lines[i].replace(/\r$/, '');
    const line = rawLine.trim();
    const indent = rawLine.length - rawLine.trimStart().length;

    // Empty line ΓÇö close open structures, add spacing
    if (!line) {
      closeList();
      closeTableFull();
      formatted.push('<div class="h-4"></div>');
      continue;
    }

    // Separator lines (---, ===, etc. but NOT markdown --- inside tables)
    if (line.match(/^[-=_]{3,}$/) && !inTable) {
      closeList();
      closeTableFull();
      continue;
    }

    // ΓöÇΓöÇ Markdown blockquotes: > text ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // Consecutive > lines are grouped into one block so multi-line notes render
    // correctly. If the first line is a recognised source/caution label it is
    // rendered as a styled callout; otherwise a plain blockquote.
    if (line.startsWith('> ') || line === '>') {
      closeList();
      closeTableFull();

      // Collect all consecutive > lines (including the current one at index i)
      const bqLines: string[] = [];
      while (i < lines.length) {
        const rawL = lines[i].replace(/\r$/, '');
        const l = rawL.trim();
        if (l.startsWith('> ') || l === '>') {
          bqLines.push(l.replace(/^>\s?/, ''));
          i++;
        } else {
          break;
        }
      }
      i--; // outer for-loop will i++ at end of iteration

      // Detect source/caution note label on the first line
      const NOTE_PATTERN =
        /^(Authenticity Note|Scholarly Caution|Historical Note|Source Note|Study Note|Editor Review Needed):?$/i;
      const labelMatch = bqLines[0]?.match(NOTE_PATTERN);

      if (labelMatch) {
        const labelText = labelMatch[1];
        const rest = bqLines.slice(1).filter(l => l.trim());
        const bodyHtml = rest.map(l => applyInlineFormatting(l)).join(' ');
        formatted.push(
          `<div class="seerah-callout">` +
          `<span class="seerah-callout-label">${escapeHtml(labelText)}</span>` +
          (bodyHtml ? `<span class="seerah-callout-body">${bodyHtml}</span>` : '') +
          `</div>`
        );
      } else {
        const bqHtml = bqLines.map(l => applyInlineFormatting(l)).join(' ');
        formatted.push(`<blockquote>${bqHtml}</blockquote>`);
      }

      firstContentSeen = true;
      continue;
    }

    // ΓöÇΓöÇ Markdown headings: #, ##, ### ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const mdHeading = line.match(/^(#{1,6})\s+(.*)/);
    if (mdHeading) {
      closeList();
      closeTableFull();
      const level = mdHeading[1].length;
      const headingText = mdHeading[2].trim();
      if (level === 1) {
        // H1 = document title ΓÇö skip (TextViewer shows its own article header)
        firstContentSeen = true;
        continue;
      } else if (level === 2) {
        formatted.push(`<h2 class="seerah-h2">${escapeHtml(headingText)}</h2>`);
      } else {
        formatted.push(`<h3 class="seerah-h3"><span class="seerah-h3-bar"></span>${escapeHtml(headingText)}</h3>`);
      }
      firstContentSeen = true;
      continue;
    }

    // ΓöÇΓöÇ Markdown pipe tables: | col | col | ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (line.startsWith('|')) {
      closeList();
      firstContentSeen = true;

      // Separator row (|---|---| or |:---:|---:| etc.) ΓÇö closes thead, opens tbody
      if (line.match(/^\|[\s\-:|]+\|/)) {
        closePipeTableHeader();
        continue;
      }

      // Parse cells: split on | and discard first/last empty segments
      const cells = line.split('|').slice(1, -1).map(c => c.trim());

      if (!inTable) {
        // First row = header
        formatted.push('<table class="seerah-data-table"><thead><tr>');
        cells.forEach(c => formatted.push(`<th>${escapeHtml(c)}</th>`));
        inTable = true;
        pipeTableHeaderOpen = true;
      } else if (pipeTableHeaderOpen) {
        // Shouldn't happen in standard markdown, but handle extra header rows gracefully
        cells.forEach(c => formatted.push(`<th>${escapeHtml(c)}</th>`));
      } else {
        // Data row
        const rowCells = cells.map(c => `<td>${applyInlineFormatting(c)}</td>`).join('');
        formatted.push(`<tr>${rowCells}</tr>`);
      }
      continue;
    }

    // ΓöÇΓöÇ Tab-separated table rows ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // IMPORTANT: check rawLine (not trimmed line) ΓÇö trailing tabs are stripped by trim()
    // e.g. "bin Abdullah\t" becomes "bin Abdullah" after trim, hiding the tab.
    if (rawLine.includes('\t')) {
      closeList();
      closePipeTableHeader();
      // Split rawLine and trim each cell individually
      const cols = rawLine.split('\t').map(c => c.trim());

      if (!inTable) {
        // Look ahead: if the next non-empty line is also tab-delimited ΓåÆ this row is a header
        let nextIsTab = false;
        for (let j = i + 1; j < lines.length; j++) {
          const nextRaw = lines[j].replace(/\r$/, '');
          const nextLine = nextRaw.trim();
          if (nextLine) { nextIsTab = nextRaw.includes('\t'); break; }
        }

        if (nextIsTab) {
          formatted.push('<table class="seerah-data-table"><thead><tr>');
          cols.forEach(c => formatted.push(c ? `<th>${escapeHtml(c)}</th>` : '<th></th>'));
          formatted.push('</tr></thead><tbody>');
          inTable = true;
        } else {
          // Single isolated tab row ΓÇö render as a one-row table body
          formatted.push('<table class="seerah-data-table"><tbody><tr>');
          cols.forEach(c => formatted.push(`<td>${applyInlineFormatting(c)}</td>`));
          formatted.push('</tr></tbody></table>');
        }
      } else {
        const rowCells = cols.map(c => `<td>${applyInlineFormatting(c)}</td>`).join('');
        formatted.push(`<tr>${rowCells}</tr>`);
      }
      firstContentSeen = true;
      continue;
    }

    // Non-table/non-heading content ΓÇö close any open table
    closeTableFull();

    // Skip document title line in plain-text format (e.g. "Briefing: The Pre-Islamic Arabian Context").
    // TextViewer already renders its own article header.
    if (!firstContentSeen && line.match(/^(Briefing|Study Guide|Report)\s*[:\-ΓÇô]/i)) {
      firstContentSeen = true;
      continue;
    }
    firstContentSeen = true;

    // ΓöÇΓöÇ H2 Headings (plain-text format) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (
      (line === line.toUpperCase() && line.length > 3 && !line.match(/^\d/)) ||
      line.match(/^(Executive Summary|Summary|Introduction|Conclusion|Background|Overview|Key Points|Important Notes?|Context|Analysis):?$/i)
    ) {
      closeList();
      formatted.push(`<h2 class="seerah-h2">${escapeHtml(line.replace(/:$/, ''))}</h2>`);
      continue;
    }

    // ΓöÇΓöÇ H3 Section headings (plain-text format) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (isSectionHeading(line)) {
      closeList();
      formatted.push(`<h3 class="seerah-h3"><span class="seerah-h3-bar"></span>${escapeHtml(line)}</h3>`);
      continue;
    }

    // ΓöÇΓöÇ Lists ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

    // Nested bullet (ΓëÑ2 spaces of indentation + bullet marker)
    if (indent >= 2 && line.match(/^[*\-ΓÇó]\s/)) {
      if (!inList) {
        formatted.push('<ul class="seerah-list">');
        inList = true;
      }
      if (!inNestedList) {
        formatted.push('<ul class="seerah-nested-list">');
        inNestedList = true;
      }
      const cleanLine = line.replace(/^[*\-ΓÇó]\s*/, '');
      formatted.push(`<li class="seerah-li seerah-nested-li">${applyInlineFormatting(cleanLine)}</li>`);
      continue;
    }

    // Top-level bullet or numbered list item
    if (line.match(/^[ΓÇó\-*]\s/) || line.match(/^\d+[.)]\s/)) {
      closeNestedList();
      if (!inList) {
        formatted.push('<ul class="seerah-list">');
        inList = true;
      }
      const cleanLine = line.replace(/^[*\-ΓÇó]\s*/, '').replace(/^\d+[.)]\s*/, '');
      // Label bullets: short text ending with ":" act as mini sub-headings
      const isLabel = cleanLine.endsWith(':') && cleanLine.length <= 50 && !cleanLine.includes('.');
      if (isLabel) {
        formatted.push(`<li class="seerah-li seerah-li-label">${applyInlineFormatting(cleanLine)}</li>`);
      } else {
        formatted.push(`<li class="seerah-li">${applyInlineFormatting(cleanLine)}</li>`);
      }
      continue;
    }

    // Non-list content ΓÇö close any open list
    closeList();

    // ΓöÇΓöÇ Quranic verse / Hadith quote ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // Paragraphs starting with an opening quote that end with a known citation.
    const isQuranRef = /\(\s*(?:[A-Z][a-zA-Z\s\u00C0-\u024F-]*\s+)?\d+:\d+[^)]*\)\s*$/.test(line);
    const isHadithRef = /\(\s*(?:ß╣óaß╕Ñ─½ß╕Ñ\s+|Sahih\s+|Sunan\s+|Musnad\s+)?(?:Bukh[a─ü]r[i─½]|Muslim|Tirmidh[i─½]|Abu\s+Dawud|Nas[a─ü][i─½]|Ibn\s+Majah|Ahmad|Muwatt[a─ü])[^)]*\)\s*$/i.test(line);
    if (/^["""]/.test(line) && (isQuranRef || isHadithRef)) {
      const label = isQuranRef ? 'Quranic Verse' : 'Hadith';
      formatted.push(`<blockquote class="seerah-verse"><span class="seerah-verse-label">${label}</span>${applyInlineFormatting(line)}</blockquote>`);
      continue;
    }

    // Regular paragraph
    formatted.push(`<p class="seerah-p">${applyInlineFormatting(line)}</p>`);
  }

  // Close any still-open structures
  closeList();
  closeTableFull();

  return formatted.join('\n');
}

/**
 * seed-assets.ts
 *
 * Scans the local Seerah-data directory and inserts one SeerahPartAsset row
 * per discovered file into Supabase (via Prisma).
 *
 * Asset types written:
 *   video ┬╖ audio ┬╖ mindmap
 *   infographic_concise ┬╖ infographic_standard ┬╖ infographic_bento
 *   briefing ┬╖ statement_of_facts ┬╖ study_guide ┬╖ report
 *   flashcards ┬╖ quiz_data
 *   slide_presented ┬╖ slide_detailed ┬╖ slide_facts
 *
 * Run:  npx tsx prisma/seed-assets.ts
 */

import { PrismaClient } from "@prisma/client";
import fs from "fs";
import path from "path";

import {
  SEERAH_ROOT,
  videoExists,
  audioExists,
  getAudioFilename,
  mindmapExists,
  getInfographicFilename,
  getSlideFiles,
  readBriefing,
  readStatementOfFacts,
  readStudyGuide,
  readReport,
  readFlashcards,
  readQuiz,
} from "../lib/files";

const prisma = new PrismaClient();

const pad2 = (n: number) => String(n).padStart(2, "0");

// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

type AssetRow = {
  assetType: string;
  title: string;
  url: string | null;
  filePath: string | null;
  assetOrder: number;
  metadataJson: string | null;
};

function assetsForPart(partNum: number): AssetRow[] {
  const rows: AssetRow[] = [];
  const n = partNum;

  // ΓöÇΓöÇ Video ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  if (videoExists(n)) {
    rows.push({
      assetType:    "video",
      title:        `Part ${n} ΓÇö Video`,
      url:          `/api/media/video/${n}`,
      filePath:     `Videos/Part ${n}.mp4`,
      assetOrder:   0,
      metadataJson: null,
    });
  }

  // ΓöÇΓöÇ Audio ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const audioFile = getAudioFilename(n);
  if (audioFile) {
    rows.push({
      assetType:    "audio",
      title:        `Part ${n} ΓÇö Audio`,
      url:          `/api/media/audio/${n}`,
      filePath:     `Audio/${audioFile}`,
      assetOrder:   0,
      metadataJson: null,
    });
  }

  // ΓöÇΓöÇ Mindmap ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  if (mindmapExists(n)) {
    rows.push({
      assetType:    "mindmap",
      title:        `Part ${n} ΓÇö Mindmap`,
      url:          `/seerah-media/Mindmaps/Part ${n} - Mindmap.png`,
      filePath:     `Mindmaps/Part ${n} - Mindmap.png`,
      assetOrder:   0,
      metadataJson: null,
    });
  }

  // ΓöÇΓöÇ Infographics ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const infographicStyles = [
    { style: "Concise",    assetType: "infographic_concise" },
    { style: "Standard",   assetType: "infographic_standard" },
    { style: "Bento Grid", assetType: "infographic_bento" },
  ] as const;

  for (const { style, assetType } of infographicStyles) {
    const filename = getInfographicFilename(n, style);
    if (filename) {
      rows.push({
        assetType,
        title:        `Part ${n} ΓÇö Infographic (${style})`,
        url:          `/seerah-media/Infographics/${style}/${filename}`,
        filePath:     `Infographics/${style}/${filename}`,
        assetOrder:   0,
        metadataJson: null,
      });
    }
  }

  // ΓöÇΓöÇ Text documents (content stored in DB) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const briefing = readBriefing(n);
  if (briefing) {
    rows.push({
      assetType:    "briefing",
      title:        `Part ${n} ΓÇö Briefing`,
      url:          null,
      filePath:     `Briefing/Part ${n} Briefing Document.txt`,
      assetOrder:   0,
      metadataJson: briefing,
    });
  }

  const sof = readStatementOfFacts(n);
  if (sof) {
    rows.push({
      assetType:    "statement_of_facts",
      title:        `Part ${n} ΓÇö Statement of Facts`,
      url:          null,
      filePath:     `StatementOfFacts/Part ${n} - Statement of Facts.txt`,
      assetOrder:   0,
      metadataJson: sof,
    });
  }

  const guide = readStudyGuide(n);
  if (guide) {
    rows.push({
      assetType:    "study_guide",
      title:        `Part ${n} ΓÇö Study Guide`,
      url:          null,
      filePath:     `Studyguides/Part ${n} - Study Guide.txt`,
      assetOrder:   0,
      metadataJson: guide,
    });
  }

  const report = readReport(n);
  if (report) {
    rows.push({
      assetType:    "report",
      title:        `Part ${n} ΓÇö Report`,
      url:          null,
      filePath:     null,           // variable filename ΓÇö content stored in DB
      assetOrder:   0,
      metadataJson: report,
    });
  }

  // ΓöÇΓöÇ Flashcards (JSON stored in DB) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const flashcards = readFlashcards(n);
  if (flashcards) {
    rows.push({
      assetType:    "flashcards",
      title:        `Part ${n} ΓÇö Flashcards`,
      url:          null,
      filePath:     `Flashcards/Part_${pad2(n)}.json`,
      assetOrder:   0,
      metadataJson: JSON.stringify(flashcards),
    });
  }

  // ΓöÇΓöÇ Quiz data (JSON stored in DB) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const quiz = readQuiz(n);
  if (quiz) {
    rows.push({
      assetType:    "quiz_data",
      title:        `Part ${n} ΓÇö Quiz`,
      url:          null,
      filePath:     `Quizzes/Part_${pad2(n)}.json`,
      assetOrder:   0,
      metadataJson: JSON.stringify(quiz),
    });
  }

  // ΓöÇΓöÇ Slides ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const slideTypes = [
    { type: "presented" as const, assetType: "slide_presented" },
    { type: "detailed"  as const, assetType: "slide_detailed"  },
    { type: "facts"     as const, assetType: "slide_facts"     },
  ];

  for (const { type, assetType } of slideTypes) {
    const files = getSlideFiles(n, type);
    files.forEach((relPath, i) => {
      rows.push({
        assetType,
        title:        `Part ${n} ΓÇö ${type.charAt(0).toUpperCase() + type.slice(1)} Slide ${i + 1}`,
        url:          `/api/media/slides/${relPath}`,
        filePath:     relPath,
        assetOrder:   i,
        metadataJson: null,
      });
    });
  }

  return rows;
}

// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

async function main() {
  console.log("\nΓåÆ Seerah asset seeder");
  console.log(`  Data root : ${SEERAH_ROOT}`);
  console.log(`  Exists    : ${fs.existsSync(SEERAH_ROOT)}\n`);

  if (!fs.existsSync(SEERAH_ROOT)) {
    console.error("Γ£ù Seerah-data directory not found. Set SEERAH_DATA_DIR env var if it's in a non-default location.");
    process.exit(1);
  }

  const parts = await prisma.seerahPart.findMany({ orderBy: { partNumber: "asc" } });
  console.log(`  Parts in DB: ${parts.length}\n`);

  let totalCreated = 0;
  const summary: Record<string, number> = {};

  for (const part of parts) {
    const n = part.partNumber;
    const rows = assetsForPart(n);

    if (rows.length === 0) {
      console.log(`  Part ${String(n).padStart(3)}: ΓÇö (no assets found)`);
      continue;
    }

    // Wipe existing assets for this part then re-insert
    await prisma.seerahPartAsset.deleteMany({ where: { seerahPartId: part.id } });

    await prisma.seerahPartAsset.createMany({
      data: rows.map((r) => ({
        seerahPartId: part.id,
        assetType:    r.assetType,
        title:        r.title,
        url:          r.url,
        filePath:     r.filePath,
        assetOrder:   r.assetOrder,
        metadataJson: r.metadataJson,
        isActive:     true,
      })),
    });

    totalCreated += rows.length;

    // Tally by type
    for (const r of rows) {
      summary[r.assetType] = (summary[r.assetType] ?? 0) + 1;
    }

    const types = [...new Set(rows.map((r) => r.assetType))].join(", ");
    console.log(`  Part ${String(n).padStart(3)}: ${String(rows.length).padStart(3)} assets  [${types}]`);
  }

  console.log("\nΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ");
  console.log("  Asset type breakdown:");
  for (const [type, count] of Object.entries(summary).sort()) {
    console.log(`    ${type.padEnd(24)} ${count}`);
  }
  console.log("ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ");
  console.log(`  Total rows inserted: ${totalCreated}`);
  console.log("Γ£ô Done.\n");
}

main().catch((e) => { console.error(e); process.exit(1); }).finally(() => prisma.$disconnect());

/**
 * Readability Audit Script ΓÇö scans all 100 Seerah parts via the local API.
 *
 * Usage (run while `npm run dev` is active):
 *   npx ts-node --project tsconfig.json scripts/audit-readability.ts
 *   -- or --
 *   npx tsx scripts/audit-readability.ts
 *
 * Output:
 *   reports/readability-audit.json
 *   reports/readability-audit.csv
 *   reports/READABILITY-AUDIT-SUMMARY.md
 */

import fs from "fs";
import path from "path";

// ΓöÇΓöÇΓöÇ Config ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const BASE_URL = process.env.AUDIT_BASE_URL ?? "http://localhost:3000";
const TOTAL_PARTS = 100;
const OUT_DIR = path.join(__dirname, "..", "reports");

// ΓöÇΓöÇΓöÇ Types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

type Severity = "high" | "medium" | "low";
type ResourceType = "briefing" | "facts" | "study_guide" | "report";
type IssueType =
  | "tab_table_unrendered"
  | "genealogy_chain_unstructured"
  | "name_notes_mixed_in_list"
  | "repeated_short_lines_not_bullets"
  | "encoding_corruption"
  | "dense_paragraph_no_headings"
  | "caution_note_buried"
  | "comparison_not_structured"
  | "nested_bullets_flattened"
  | "missing_content";
type FixSource = "renderer" | "source_content" | "both";

interface Issue {
  partNumber: number;
  resourceType: ResourceType;
  section: string;
  issueType: IssueType;
  severity: Severity;
  problem: string;
  recommendation: string;
  fixSource: FixSource;
  affectsLaunch: boolean;
}

interface PartContent {
  briefingText: string | null;
  statementOfFactsText: string | null;
  studyGuideText: string | null;
  reportText: string | null;
}

// ΓöÇΓöÇΓöÇ Fetch ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

async function fetchPartContent(partNum: number, retries = 2): Promise<PartContent | null> {
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      const res = await fetch(`${BASE_URL}/api/part/${partNum}/content`, {
        signal: AbortSignal.timeout(15_000),
      });
      if (!res.ok) return null;
      return (await res.json()) as PartContent;
    } catch {
      if (attempt < retries) {
        await new Promise(r => setTimeout(r, 500 * (attempt + 1)));
      }
    }
  }
  return null;
}

// ΓöÇΓöÇΓöÇ Detectors ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function detectTabTable(text: string): boolean {
  return text.includes("\t");
}

function detectEncodingCorruption(text: string): boolean {
  // Mojibake patterns: replacement character or suspicious ? sequences
  return /\uFFFD|[^\x00-\x7F\u0600-\u06FF\u0750-\u077F\s]{3,}/.test(text);
}

function detectGenealogyChain(text: string): { found: boolean; lineCount: number } {
  const lines = text.split("\n").map(l => l.trim()).filter(Boolean);
  const genealogyPattern = /\bbin\b|\bbint\b/i;
  const matchingLines = lines.filter(l => genealogyPattern.test(l));
  return { found: matchingLines.length >= 3, lineCount: matchingLines.length };
}

function detectNameNotes(text: string): { found: boolean; count: number } {
  const lines = text.split("\n").map(l => l.trim()).filter(Boolean);
  const nameNotePattern = /\bname was\b|\bwas called\b|\balso called\b|\bknown as\b/i;
  const matches = lines.filter(l => nameNotePattern.test(l));
  return { found: matches.length >= 2, count: matches.length };
}

function detectRepeatedShortLines(text: string): { found: boolean; clusters: number } {
  const lines = text.split("\n").map(l => l.trim()).filter(Boolean);
  let clusters = 0;
  let streak = 0;
  for (const line of lines) {
    // Short factual sentence, not already a bullet/heading
    if (line.length > 10 && line.length < 120 && line.endsWith(".") && !line.startsWith("*") && !line.startsWith("-")) {
      streak++;
      if (streak === 4) clusters++; // count once per cluster of 4+
    } else {
      streak = 0;
    }
  }
  return { found: clusters > 0, clusters };
}

function detectCautionNote(text: string): boolean {
  const cautionPhrases = [
    /not treated as.{0,40}authenticated/i,
    /reports differ/i,
    /stronger view is/i,
    /should not be overstated/i,
    /requires caution/i,
    /narration.{0,30}weak/i,
    /lack.{0,30}certainty/i,
    /transmitted tradition/i,
    /less certain/i,
  ];
  return cautionPhrases.some(r => r.test(text));
}

function detectDenseParagraphs(text: string): boolean {
  const paragraphs = text.split(/\n\s*\n/).map(p => p.trim());
  return paragraphs.some(p => p.length > 600 && !p.includes("\n"));
}

function detectMissingHeadings(text: string): boolean {
  const wordCount = text.split(/\s+/).length;
  // Long content with no heading-like lines
  if (wordCount < 200) return false;
  const lines = text.split("\n").map(l => l.trim()).filter(Boolean);
  const headingLike = lines.filter(
    l =>
      (l === l.toUpperCase() && l.length > 3) ||
      (l.match(/^[A-Z]/) && l.endsWith(":") && l.length < 80) ||
      l.match(/^#+\s/)
  );
  return headingLike.length === 0;
}

function detectNestedBullets(text: string): boolean {
  // Indented bullets that might be flattened by renderer
  return /^ {2,}[\*\-ΓÇó]\s/m.test(text);
}

// ΓöÇΓöÇΓöÇ Audit a single resource ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function auditResource(
  partNumber: number,
  resourceType: ResourceType,
  text: string | null
): Issue[] {
  const issues: Issue[] = [];

  if (!text) {
    if (resourceType === "briefing") {
      issues.push({
        partNumber,
        resourceType,
        section: "(entire resource)",
        issueType: "missing_content",
        severity: "high",
        problem: "Briefing text is missing or could not be loaded.",
        recommendation: "Upload briefing file to R2 / check filename convention.",
        fixSource: "source_content",
        affectsLaunch: true,
      });
    }
    return issues;
  }

  // Tab-separated tables unrendered
  if (detectTabTable(text)) {
    issues.push({
      partNumber,
      resourceType,
      section: "table section",
      issueType: "tab_table_unrendered",
      severity: resourceType === "briefing" ? "high" : "medium",
      problem: "Content contains tab-separated columns that render as plain text without structure.",
      recommendation: "Renderer now handles tab tables ΓÇö verify visually. If still broken, source may need re-encoding.",
      fixSource: "renderer",
      affectsLaunch: resourceType === "briefing",
    });
  }

  // Encoding corruption
  if (detectEncodingCorruption(text)) {
    issues.push({
      partNumber,
      resourceType,
      section: "(throughout)",
      issueType: "encoding_corruption",
      severity: "medium",
      problem: "Text contains garbled/corrupted characters (possible UTF-8 encoding issue in source file).",
      recommendation: "Re-save source file as UTF-8 without BOM. Check for Windows-1252 encoding artifacts.",
      fixSource: "source_content",
      affectsLaunch: false,
    });
  }

  // Genealogy chain not structured
  const genealogy = detectGenealogyChain(text);
  if (genealogy.found) {
    issues.push({
      partNumber,
      resourceType,
      section: "genealogy/lineage section",
      issueType: "genealogy_chain_unstructured",
      severity: resourceType === "facts" ? "high" : "medium",
      problem: `${genealogy.lineCount} "bin/bint" genealogy lines appear as plain numbered/bulleted items without visual chain structure.`,
      recommendation:
        "Renderer or source: separate main lineage from name-notes. Render lineage as a vertical chain card with gold accents.",
      fixSource: "both",
      affectsLaunch: partNumber <= 15,
    });
  }

  // Name notes mixed in
  const nameNotes = detectNameNotes(text);
  if (nameNotes.found) {
    issues.push({
      partNumber,
      resourceType,
      section: "name notes",
      issueType: "name_notes_mixed_in_list",
      severity: "low",
      problem: `${nameNotes.count} "was called / name was" notes are scattered inline with lineage or body text.`,
      recommendation:
        'Group into a "Name Notes" or "Also Known As" callout section for easier scanning.',
      fixSource: "both",
      affectsLaunch: false,
    });
  }

  // Repeated short lines
  const shortLines = detectRepeatedShortLines(text);
  if (shortLines.found) {
    issues.push({
      partNumber,
      resourceType,
      section: "fact/list section",
      issueType: "repeated_short_lines_not_bullets",
      severity: "medium",
      problem: `Found ${shortLines.clusters} cluster(s) of 4+ consecutive short sentences that should be a bullet list.`,
      recommendation:
        "Convert clusters of short factual sentences to bullet lists in source. Low-risk auto-fix candidate.",
      fixSource: "source_content",
      affectsLaunch: false,
    });
  }

  // Caution note buried
  if (detectCautionNote(text)) {
    issues.push({
      partNumber,
      resourceType,
      section: "caution/authenticity note",
      issueType: "caution_note_buried",
      severity: "low",
      problem:
        'Authenticity warning or scholarly caution language is present but rendered as regular paragraph text.',
      recommendation:
        'Style as a muted gold callout with label "Authenticity Note" or "Scholarly Caution". Renderer improvement.',
      fixSource: "renderer",
      affectsLaunch: false,
    });
  }

  // Dense paragraphs
  if (detectDenseParagraphs(text)) {
    issues.push({
      partNumber,
      resourceType,
      section: "long paragraph",
      issueType: "dense_paragraph_no_headings",
      severity: "low",
      problem: "One or more paragraphs exceed 600 characters without an internal line break.",
      recommendation:
        "Split at sentence boundaries where logical. Flag for human review ΓÇö do not auto-split.",
      fixSource: "source_content",
      affectsLaunch: false,
    });
  }

  // Missing headings in long content
  if (detectMissingHeadings(text)) {
    issues.push({
      partNumber,
      resourceType,
      section: "(entire resource)",
      issueType: "dense_paragraph_no_headings",
      severity: "low",
      problem: "Long content block has no discernible heading structure.",
      recommendation:
        "Add section headings to source content. Requires human judgment ΓÇö do not auto-add.",
      fixSource: "source_content",
      affectsLaunch: false,
    });
  }

  // Nested bullets that were previously flattened
  if (detectNestedBullets(text)) {
    issues.push({
      partNumber,
      resourceType,
      section: "nested list section",
      issueType: "nested_bullets_flattened",
      severity: "low",
      problem:
        "Source contains indented bullet items (2+ spaces + *). These were previously rendered as flat bullets.",
      recommendation:
        "Renderer now detects indentation and renders nested lists ΓÇö verify visually.",
      fixSource: "renderer",
      affectsLaunch: false,
    });
  }

  return issues;
}

// ΓöÇΓöÇΓöÇ CSV helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function csvEscape(value: string | number | boolean): string {
  const str = String(value);
  if (str.includes(",") || str.includes('"') || str.includes("\n")) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
}

