  const command = new ListObjectsV2Command({
    Bucket: BUCKET,
    Prefix: "videos/",
  });

  const response = await r2Client.send(command);
  
  if (!response.Contents) return [];
  
  return response.Contents
    .filter(item => item.Key.endsWith(".mp4") || item.Key.endsWith(".webm"))
    .map(item => item.Key);
}

